const places = [

  // ═══════════════════════════════════════════
  // GILGIT-BALTISTAN
  // ═══════════════════════════════════════════

  { name: "Hunza Valley", lat: 36.3167, lng: 74.6500, category: "valley", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "April to October", description: "Hunza Valley is one of Pakistan's most spectacular destinations, nestled between towering peaks including Rakaposhi, Ultar Sar, and Lady Finger. Known for its breathtaking vistas of glaciers, ancient forts, and apricot orchards. The warm hospitality of the Hunzakuts makes it truly unforgettable.", history: "Hunza was an independent princely state for centuries, ruled by the Mirs of Hunza. Its strategic position along the ancient Silk Road made it a crossroads of cultures connecting China, Central Asia, and the Indian subcontinent. The state acceded to Pakistan in 1974. The valley's people are predominantly Ismaili Muslims known for extraordinary longevity and high literacy.", image: "https://picsum.photos/seed/HunzaValley/800/400" },
  { name: "Karimabad", lat: 36.3200, lng: 74.6533, category: "city", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "April to October", description: "Karimabad is the cultural heart of Hunza, perched on a hillside with magnificent views of Rakaposhi and Ultar Sar peaks. Its bazaars sell local crafts, gemstones, and dried fruits. The famous Baltit and Altit forts are both accessible from here.", history: "Karimabad (formerly Baltit) served as the capital of the Hunza princely state for centuries. It was renamed in honor of Shah Karim Al-Husayni, the Aga Khan IV, spiritual leader of the Ismaili community that predominates in the valley.", image: "https://picsum.photos/seed/Karimabad/800/400" },
  { name: "Baltit Fort", lat: 36.3217, lng: 74.6580, category: "historical", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "April to October", description: "Baltit Fort is a magnificent 700-year-old castle perched dramatically above Karimabad, displaying a blend of Tibetan and local architectural styles. Beautifully restored by the Aga Khan Trust for Culture, it offers panoramic views of Rakaposhi, Ultar Sar, and the entire valley.", history: "Built approximately 700 years ago, Baltit Fort was home to the Mirs of Hunza for centuries. It underwent many renovations incorporating Tibetan influences brought by a Balti princess. The Aga Khan Trust undertook a major restoration in the 1990s and it is now a UNESCO-recognized heritage site.", image: "https://picsum.photos/seed/BaltitFort/800/400" },
  { name: "Altit Fort", lat: 36.2981, lng: 74.6431, category: "historical", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "April to October", description: "Altit Fort is considered one of the oldest forts in Pakistan at approximately 900 years old, perched on a 300-meter cliff above the Hunza River. The nearby Altit village has been beautifully preserved as a living cultural heritage site.", history: "Altit Fort predates Baltit Fort and was the original seat of power for the Hunza rulers. The village below, the 'Old Village', has been restored by the Aga Khan Cultural Service and preserves traditional Hunzakuts architecture and lifestyle.", image: "https://picsum.photos/seed/AltitFort/800/400" },
  { name: "Attabad Lake", lat: 36.3508, lng: 74.8618, category: "lake", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "May to September", description: "Attabad Lake is a stunning turquoise lake formed by a massive 2010 landslide. It stretches 21 km with brilliant blue-green waters contrasting against surrounding mountains. Boat rides offer spectacular views of the Karakoram peaks above.", history: "The lake formed when a massive landslide on January 4, 2010 blocked the Hunza River, displacing 6,000 people and submerging 19 km of the Karakoram Highway. Chinese-built tunnels completed in 2015 restored connectivity. What was a tragedy has become one of Pakistan's most photographed attractions.", image: "https://picsum.photos/seed/AttabadLake/800/400" },
  { name: "Eagle's Nest Hunza", lat: 36.3450, lng: 74.6650, category: "mountain", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "April to October", description: "Eagle's Nest is a viewpoint high above Karimabad offering what many consider the most spectacular mountain panorama in the world. At sunset, peaks including Rakaposhi, Diran, Ultar Sar, and Lady Finger turn golden against a crimson sky.", history: "Eagle's Nest was developed as a tourist viewpoint taking advantage of its extraordinary elevation above the Hunza Valley. Photographers and mountaineers use it as a base for acclimatization and reconnaissance of the surrounding Karakoram peaks.", image: "https://picsum.photos/seed/EaglesNestHunza/800/400" },
  { name: "Passu Cones", lat: 36.4750, lng: 74.8817, category: "mountain", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "May to October", description: "The Passu Cones (Passu Cathedral) are extraordinary sharp rock spires rising dramatically from the valley floor. Their jagged silhouettes have made them one of the most photographed mountain formations in Pakistan. The famous Hussaini Suspension Bridge nearby adds to the drama.", history: "The Passu Cones formed through millions of years of glacial erosion on the Batura Massif. The area has been inhabited by the Wakhi people for centuries. Construction of the Karakoram Highway in the 1970s opened this remote area to travelers.", image: "https://picsum.photos/seed/PassuCones/800/400" },
  { name: "Hussaini Suspension Bridge", lat: 36.4833, lng: 74.8917, category: "mountain", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "May to September", description: "One of the most thrilling and precarious bridges in the world, spanning the Hunza River near Passu. Made of wooden planks and wire rope with gaps between boards adding to the adventure. Brave travelers cross it for a short trek to Hussaini village.", history: "The bridge was built to provide connectivity for the Wakhi people of Hussaini village. The original rope bridges were gradually improved though the current version still maintains its adventurous character. It has become a popular challenge for tourists visiting the Passu area.", image: "https://picsum.photos/seed/HussainiBridge/800/400" },
  { name: "Khunjerab Pass", lat: 36.8475, lng: 75.4144, category: "mountain", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "May to October", description: "Khunjerab Pass at 4,693m is one of the highest paved international border crossings in the world, connecting Pakistan with China. Home to rare wildlife including Marco Polo sheep, snow leopards, and Himalayan ibex. The dramatic landscape of barren peaks and vast plains stretching into China is extraordinary.", history: "The pass has been a Silk Road route for over 2,000 years. The modern Karakoram Highway, a joint China-Pakistan project completed in 1978, transformed this ancient trade route into a modern road, cementing the strategic friendship between the two nations.", image: "https://picsum.photos/seed/KhunjerabPass/800/400" },
  { name: "Batura Glacier", lat: 36.5500, lng: 74.5500, category: "mountain", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "June to September", description: "One of the longest glaciers outside polar regions, stretching over 57 km in the Hunza Valley. The glacier's icefall visible from the Karakoram Highway is a spectacular sight of blue-white ice. Trekking to the glacier snout offers an up-close experience with nature's most impressive features.", history: "Batura Glacier has been documented by explorers since the 19th century and has been the subject of extensive glaciological research. The area around the glacier is traditionally used by Wakhi herders for summer pastures.", image: "https://picsum.photos/seed/BaturaGlacier/800/400" },
  { name: "Fairy Meadows", lat: 35.3856, lng: 74.5800, category: "valley", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "June to September", description: "Fairy Meadows is a breathtaking alpine meadow at 3,300m providing the most iconic view of Nanga Parbat. The lush green meadow surrounded by dense pine forests with the massive 'Killer Mountain' towering above is a scene of unparalleled beauty. Popular base for Nanga Parbat base camp treks.", history: "Named by German climbers who first explored the area in the 1930s. The first serious attempt on Nanga Parbat was by Willi Merkl's 1932 expedition. Hermann Buhl made the first successful solo summit in 1953. Fairy Meadows became accessible to tourists with a jeep track in the 1980s.", image: "https://picsum.photos/seed/FairyMeadows/800/400" },
  { name: "Nanga Parbat Base Camp (Raikot)", lat: 35.2500, lng: 74.5891, category: "mountain", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "July to September", description: "Nanga Parbat (8,126m), the world's ninth highest mountain, is known as the 'Killer Mountain.' The Raikot base camp trek offers spectacular views of the massive face. The surrounding landscape of glaciers, moraines, and alpine meadows is magnificent.", history: "Hermann Buhl made the first ascent on July 3, 1953 in a remarkable solo push without oxygen. Before this, numerous expeditions attempted the mountain at great cost — the 1934 and 1937 expeditions each ended in disaster. The mountain continues to be one of the most challenging 8,000-meter peaks.", image: "https://picsum.photos/seed/NangaParbatBC/800/400" },
  { name: "Gilgit City", lat: 35.9224, lng: 74.3084, category: "city", province: "Gilgit-Baltistan", rating: 4.2, bestTime: "March to November", description: "Gilgit City is the administrative capital of Gilgit-Baltistan, situated at the confluence of the Gilgit and Hunza rivers. The city serves as gateway to world-famous trekking destinations and mountain peaks. Its bazaars are full of dried fruits, gemstones, and traditional Gilgiti handicrafts.", history: "Gilgit has been an important Silk Road crossroads for over 2,000 years. During the British colonial era it was a strategic outpost known as the 'Gilgit Agency.' The famous Gilgit Scripts, copper-scroll Buddhist texts discovered in 1931, demonstrated the city's historical importance as a Buddhist center.", image: "https://picsum.photos/seed/GilgitCity/800/400" },
  { name: "Naltar Valley", lat: 36.1614, lng: 74.1847, category: "valley", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "May to September", description: "Famous for three beautiful lakes — Blue Lake, Red Lake, and Green Lake — each with distinctively colored water. The valley is also home to Pakistan's only ski resort and dense pine forests. The unique colored lakes are formed by glacial meltwater carrying different mineral deposits.", history: "Naltar was historically used as summer pasture land by Gilgiti herders. The polo ground here is one of the oldest in the world. Pakistan's Air Force established a ski school here in the 1950s, which became the Naltar Ski Resort — the only operational ski resort in Pakistan.", image: "https://picsum.photos/seed/NaltarValley/800/400" },
  { name: "Rakaposhi View Point (Minapin)", lat: 36.1483, lng: 74.5017, category: "mountain", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "October to November", description: "This viewpoint near Minapin village offers one of Pakistan's most stunning mountain panoramas. Rakaposhi (7,788m) rises nearly 6,000m above the Hunza River Valley in one of the most dramatic vertical ascents of any mountain on Earth.", history: "Rakaposhi, meaning 'Shining Wall' in the local Burushaski language, was first climbed by British mountaineers Mike Banks and Tom Patey in 1958. It is considered a sacred mountain by the Hunzakuts people.", image: "https://picsum.photos/seed/RakaposhiView/800/400" },
  { name: "Skardu", lat: 35.2971, lng: 75.6337, category: "city", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "May to October", description: "Skardu is the main town of Baltistan, gateway to the Karakoram Range with K2 and over 60 peaks above 7,000m. Set in a wide valley surrounded by towering barren mountains, it offers access to the world's greatest trekking routes. Its unique cold desert landscape is unlike anything else in Pakistan.", history: "Skardu was the capital of the Baltistan kingdom with complex historical relations with Ladakh, Kashgar, and Kashmir. The fort (Kharpocho) was built in the 16th century by Ali Sher Khan Anchan. The region came under Dogra rule in the 19th century and became part of Pakistan in 1948.", image: "https://picsum.photos/seed/Skardu/800/400" },
  { name: "Deosai National Park", lat: 35.0167, lng: 75.5833, category: "wildlife", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "July to September", description: "One of the highest plateaus in the world at 4,114m average elevation, covering 3,000 sq km of pristine alpine landscape. Famous for extraordinary wildflower blooms in July-August and one of the last habitats of the Himalayan brown bear. The vast windswept plains feel like the top of the world.", history: "Deosai, meaning 'Land of Giants' in Balti, was the domain of supernatural beings in local folklore. The national park was established in 1993 primarily to protect the critically endangered Himalayan brown bear, whose population has recovered from under 20 to over 80 individuals.", image: "https://picsum.photos/seed/DeosaiPark/800/400" },
  { name: "Sheosar Lake", lat: 34.9786, lng: 75.4247, category: "lake", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "July to September", description: "A high-altitude alpine lake in Deosai National Park at 4,142m. The crystal-clear lake reflects surrounding snow-capped peaks and is one of the most remote lakes in Pakistan. The surrounding grasslands come alive with wildflowers in summer.", history: "Sheosar means 'Blind Lake' in the local Shina language, referencing the mysterious sudden weather changes here. The lake is fed by snowmelt and glacial streams and is surrounded by local folklore about mythical creatures.", image: "https://picsum.photos/seed/SheoharLake/800/400" },
  { name: "Satpara Lake", lat: 35.2333, lng: 75.6000, category: "lake", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "April to October", description: "A stunning natural reservoir near Skardu surrounded by bare rocky mountains and snowfields. The lake supplies drinking water to Skardu town. Ancient rock carvings near the shore are testament to the area's importance as a Silk Road waypoint.", history: "Satpara Lake has ancient Buddhist rock carvings dating to the 3rd-7th centuries CE, depicting Buddhist symbols, traders, and animals. A dam was built in 1990 for water supply and hydroelectric power.", image: "https://picsum.photos/seed/SatparaLake/800/400" },
  { name: "Shangrila Resort (Lower Kachura Lake)", lat: 35.2800, lng: 75.5833, category: "lake", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "May to September", description: "Shangrila Resort is set in a breathtaking garden surrounding the Lower Kachura Lake, also known as 'Heaven on Earth.' The resort's unique restaurant is built inside a DC-3 aircraft fuselage mounted on the lake shore. The turquoise lake surrounded by mountains is one of Pakistan's most beautiful spots.", history: "Built by Brigadier M. Aslam Khan ('Mr. Lobo') in the 1960s, inspired by James Hilton's 'Lost Horizon.' The crashed DC-3 aircraft was salvaged from the Deosai Plains and incorporated into the resort, making it one of Pakistan's most iconic destinations.", image: "https://picsum.photos/seed/ShangrilaResort/800/400" },
  { name: "Upper Kachura Lake", lat: 35.3150, lng: 75.5650, category: "lake", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "May to October", description: "A stunning deep-blue glacial lake above Skardu, reached by a short trek. The lake's vivid blue-green color and dramatic mountain backdrop make it one of the most photogenic lakes in Baltistan. Quieter and less developed than its famous Shangrila neighbor below.", history: "Upper Kachura is a natural glacial lake in a hanging valley above the main Skardu valley. Its pristine quality is maintained by its more remote location. A popular trekking destination for visitors based in Skardu.", image: "https://picsum.photos/seed/UpperKachuraLake/800/400" },
  { name: "K2 Base Camp (Concordia)", lat: 35.8800, lng: 76.5100, category: "mountain", province: "Gilgit-Baltistan", rating: 5.0, bestTime: "June to August", description: "K2 (8,611m), the world's second highest and arguably most challenging mountain. The trek to K2 Base Camp at Concordia is considered one of the greatest trekking routes on Earth, passing through the Baltoro Glacier with views of Karakoram giants. The concentration of 8,000m peaks is unmatched anywhere.", history: "K2 was first measured in 1856 by Survey of India surveyor T.G. Montgomerie. First ascent was made July 31, 1954 by Achille Compagnoni and Lino Lacedelli of an Italian expedition. Known as the 'Savage Mountain' with approximately one death per four summits.", image: "https://picsum.photos/seed/K2BaseCamp/800/400" },
  { name: "Concordia", lat: 35.8833, lng: 76.5167, category: "mountain", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "June to August", description: "Concordia is the confluence of glaciers on the Baltoro at 4,600m, offering views of four 8,000m peaks: K2, Broad Peak, Gasherbrum I and II. Called the 'Throne Room of the Mountain Gods.' Getting here requires an 8-10 day trek from Askole village.", history: "First reached by the Conway Expedition in 1892 which explored and mapped the Baltoro Glacier region. The name reflects the junction of several glaciers. This has been the starting base for countless 8,000m peak expeditions in the 20th and 21st centuries.", image: "https://picsum.photos/seed/Concordia/800/400" },
  { name: "Shigar Fort", lat: 35.5006, lng: 75.7658, category: "historical", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "May to October", description: "A beautifully restored 400-year-old fort and palace now serving as a boutique heritage hotel. Built in traditional Balti style with wooden interlocking architecture, surrounded by gardens and orchards. The Aga Khan Trust restoration has made it one of the finest heritage hotels in Asia.", history: "Shigar Fort was the seat of the Rajas of Shigar principality in Baltistan, built in the 17th century. When the Raja family vacated the fort, it deteriorated until the Aga Khan Trust undertook its restoration in 2001-2005.", image: "https://picsum.photos/seed/ShigarFort/800/400" },
  { name: "Khaplu Palace", lat: 35.1667, lng: 76.5667, category: "historical", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "May to October", description: "Khaplu Palace (Farang Mahal) is a magnificent 19th-century palace near Khaplu town with intricate wooden carvings. Restored by the Aga Khan Trust, the multi-story wooden structure now serves as a heritage hotel. The surrounding Khaplu Valley with green fields and snow-capped peaks is exceptionally scenic.", history: "Built by the Raja of Khaplu in the mid-19th century, showing strong Kashmiri and Tibetan architectural influences. The Aga Khan Trust restored the palace between 2005-2009, preserving one of Baltistan's most exceptional architectural treasures.", image: "https://picsum.photos/seed/KhapluPalace/800/400" },
  { name: "Ghizer Valley", lat: 36.1000, lng: 73.7333, category: "valley", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "May to October", description: "One of the most beautiful and least-visited valleys in Pakistan, stretching along the Ghizer River through spectacular gorges. Contains numerous smaller valleys each with its own scenery and culture. Phander and Khalti lakes are the valley's most popular attractions.", history: "Ghizer was historically part of the territories administered by the Mehtar of Chitral and later the Mirs of Yasin. The area has been inhabited by diverse ethnic groups including Kho, Wakhi, and Shina peoples whose relative remoteness preserved traditional lifestyles.", image: "https://picsum.photos/seed/GhizerValley/800/400" },
  { name: "Phander Lake", lat: 36.1500, lng: 73.4833, category: "lake", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "May to October", description: "A stunning turquoise lake in the Ghizer Valley surrounded by snow-capped mountains and green meadows. The lake's extraordinary color comes from glacial silt suspended in the water. Trout fishing is popular and the surrounding area offers excellent camping.", history: "Phander village and its lake have been an important rest stop on the historic trade route between Gilgit and Chitral. The area was part of the territories controlled by the Mehtar of Chitral before falling under British influence.", image: "https://picsum.photos/seed/PhanderLake/800/400" },
  { name: "Khalti Lake", lat: 36.2000, lng: 73.5500, category: "lake", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "May to September", description: "A beautiful blue lake in Gupis, Ghizer Valley, formed by an ancient landslide that dammed the Ghizer River. The landscape contrasts green reeds and blue water with barren rocky mountains beautifully. A significant domestic tourism destination.", history: "Khalti Lake formed when a massive landslide dammed the Ghizer River, creating a natural lake. The lake has been important for the fishing communities of Gupis and has grown as a tourism destination as awareness of the Ghizer region has grown.", image: "https://picsum.photos/seed/KhaltiLake/800/400" },
  { name: "Shandur Pass", lat: 36.0600, lng: 72.5300, category: "mountain", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "Late June to August", description: "Famous as the 'Roof of the World Polo Ground' where annual polo is played between Gilgit and Chitral teams. The high-altitude plateau at 3,734m with its flat polo ground surrounded by peaks offers a unique and spectacular setting for this ancient sport.", history: "The Shandur Pass has been a traditional boundary between Gilgit and Chitral for centuries. The polo ground is said to be one of the oldest in the world, with the game played in this region for at least 500 years. The Shandur Polo Festival was institutionalized in 1936.", image: "https://picsum.photos/seed/ShandurPass/800/400" },
  { name: "Yasin Valley", lat: 36.3667, lng: 73.3000, category: "valley", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "May to October", description: "A serene and beautiful valley north of Gilgit, relatively off the beaten track but offering some of Pakistan's finest natural scenery. Known for friendly people, ancient stone forts, and spectacular mountain views. Several high-altitude lakes can be reached by trekking.", history: "Yasin has been an independent principality for centuries, frequently contested between the rulers of Gilgit, Chitral, and Badakhshan. The British used agents from Yasin in explorations of the Hindu Kush and Karakoram in the 19th century.", image: "https://picsum.photos/seed/YasinValley/800/400" },
  { name: "Astore Valley", lat: 35.3626, lng: 74.8582, category: "valley", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "June to September", description: "A stunning alpine valley in southern Gilgit-Baltistan offering magnificent views of Nanga Parbat. Serves as key access to the Rupal Face and offers excellent trekking through forests and meadows. Rama Meadows and Rupal Valley are the valley's most famous attractions.", history: "Astore was historically an important route between the Punjab plains and the Karakoram mountains. The area was ruled by the Astore Rajas and came under British influence in the late 19th century as an important supply route.", image: "https://picsum.photos/seed/AstoreValley/800/400" },
  { name: "Rama Meadows", lat: 35.1833, lng: 74.6667, category: "valley", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "July to September", description: "A beautiful alpine meadow at 3,300m in the Astore Valley offering stunning views of Nanga Parbat's Rupal Face. Surrounded by thick coniferous forests and covered with wildflowers in summer. A popular camping spot and acclimatization point for Nanga Parbat trekkers.", history: "Rama Meadows has been traditional summer pasture for centuries. The area gained mountaineering significance when expeditions began using it as a base for attempts on Nanga Parbat's Rupal Face — the world's highest mountain face at 4,600m vertical relief.", image: "https://picsum.photos/seed/RamaMeadows/800/400" },
  { name: "Nanga Parbat Rupal Face", lat: 35.2167, lng: 74.5500, category: "mountain", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "July to September", description: "The Rupal Face of Nanga Parbat is the world's highest mountain face, rising approximately 4,600 meters from the Rupal Valley floor to the summit. The immensity of this wall of rock and ice is beyond comprehension when viewed from the valley floor.", history: "Reinhold Messner and his brother Günther made the first ascent via the Rupal Face in 1970 — successful but tragic, as Günther died during descent. In 2005, Steve House and Vince Anderson made a dramatic new route up the face, considered one of the greatest alpinism achievements ever.", image: "https://picsum.photos/seed/RupalFaceNanga/800/400" },
  { name: "Shimshal Valley", lat: 36.4700, lng: 75.3500, category: "valley", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "June to September", description: "One of Pakistan's most remote and spectacular valleys, home to a community known for producing an extraordinary number of high-altitude mountaineers. The Shimshal Pamir high-altitude plateau is one of the most remarkable landscapes in Pakistan.", history: "Shimshal has been inhabited for centuries and was historically part of the Hunza state. The village maintains a unique annual pastoral tradition where the entire community migrates to the high Shimshal Pamir plateau for summer.", image: "https://picsum.photos/seed/ShimshalValley/800/400" },
  { name: "Chipurson Valley", lat: 36.7000, lng: 74.5000, category: "valley", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "June to September", description: "A remote and spectacularly beautiful valley at the northern end of the Wakhan network near the Tajikistan border. Home to Wakhi nomads who spend summers at very high altitude pastures. The isolation, wildlife (including Marco Polo sheep), and landscape are extraordinary.", history: "Chipurson Valley is inhabited by the Wakhi people who have herded livestock in these high valleys for thousands of years. The valley is on an ancient route between the Wakhan Corridor and the Hunza region historically used for trade and migration.", image: "https://picsum.photos/seed/ChipursonValley/800/400" },
  { name: "Misgar Valley", lat: 36.7833, lng: 74.8333, category: "valley", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "June to September", description: "The last inhabited village on the Karakoram Highway before the Khunjerab Pass and the Chinese border. Offers stunning mountain scenery and a last glimpse of Pakistani culture before crossing into China. The Mintaka Pass trail is one of the ancient Silk Road routes into Central Asia.", history: "Misgar has been historically significant as the last Pakistani village on the main Silk Road route into China. During the British era it was an important frontier post monitoring cross-border movement.", image: "https://picsum.photos/seed/MisgarValley/800/400" },
  { name: "Sost", lat: 36.7000, lng: 74.7333, category: "city", province: "Gilgit-Baltistan", rating: 4.4, bestTime: "May to September", description: "Sost is the border town and dry port for China-Pakistan trade on the Karakoram Highway. The last major Pakistani settlement before Khunjerab Pass, offering access to Chipurson and Shimshal valleys. Trading activity between Pakistani and Chinese merchants gives it an interesting frontier character.", history: "Sost has been the main Pakistan-China border crossing since the Karakoram Highway opened in 1978. The town grew rapidly as a trading hub handling hundreds of millions in annual trade between the two countries.", image: "https://picsum.photos/seed/SostValley/800/400" },
  { name: "Gupis", lat: 36.1667, lng: 73.3000, category: "valley", province: "Gilgit-Baltistan", rating: 4.4, bestTime: "May to October", description: "A small town at the head of the Ghizer Valley with a beautiful lake and dramatic mountain scenery. The surrounding area offers several trekking opportunities and the Ghizer River near Gupis is excellent for trout fishing.", history: "Gupis was historically part of the territories of Yasin principality. A British political agent was stationed here during the colonial era to monitor the strategic mountain passes of the region.", image: "https://picsum.photos/seed/Gupis/800/400" },
  { name: "Karakoram Highway (KKH)", lat: 36.0000, lng: 74.5000, category: "historical", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "May to October", description: "Often called the 'Eighth Wonder of the World,' the KKH stretches 1,300 km from Islamabad to Kashgar in China through the Himalayan, Karakoram, and Pamir ranges. The drive through Pakistan's northern section is among the most spectacular road journeys on Earth.", history: "Built jointly by Pakistan and China over 20 years (1959-1979), replacing the ancient Silk Road, requiring shifting 30 million cubic meters of rock. Over 1,000 Pakistani and 80 Chinese workers died during construction. The world's highest paved international road.", image: "https://picsum.photos/seed/KarakoromHighway/800/400" },
  { name: "Chilas Petroglyphs", lat: 35.4278, lng: 74.0956, category: "historical", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "April to October", description: "The Chilas-Thalpan area has over 50,000 petroglyphs — one of the world's largest concentrations of prehistoric and historic rock art. The inscriptions span many languages including Kharoshthi, Brahmi, Sogdian, and Arabic, documenting 10,000 years of human activity.", history: "Buddhist pilgrims carved images of Buddhas and stupas while traveling the Silk Road. Merchants left records in multiple scripts. The Chilas petroglyphs are of extraordinary importance for understanding the history of trans-Himalayan trade and cultural exchange.", image: "https://picsum.photos/seed/Chilas/800/400" },
  { name: "Cold Desert Katpana (Skardu)", lat: 35.2800, lng: 75.7000, category: "desert", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "May to October", description: "The Katpana Desert is the world's highest cold desert at approximately 2,226m, featuring unique sand dunes surrounded by 6,000-meter peaks. The extraordinary contrast of golden sand dunes against snow-capped mountains is surreal. Dawn and dusk offer some of the most dramatic photography in Pakistan.", history: "The Katpana Desert was formed by wind-blown sand deposited in a broad alluvial plain of the Indus River near Skardu. Despite its high altitude it receives little precipitation, qualifying as a cold desert. The unique landscape was little known outside Baltistan before digital photography spread awareness.", image: "https://picsum.photos/seed/SkarduDesert/800/400" },
  { name: "Manthoka Waterfall", lat: 35.2083, lng: 76.5833, category: "mountain", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "June to September", description: "One of the largest and most spectacular waterfalls in the Karakoram region, near Khaplu in eastern Baltistan. The waterfall cascades dramatically from a narrow gorge and the surrounding mountain scenery is extraordinary.", history: "Manthoka (meaning 'beautiful waterfall' in Balti) is fed by glacial meltwater from surrounding mountains. It gained wider recognition as a tourist attraction as road access to eastern Baltistan improved in the early 21st century.", image: "https://picsum.photos/seed/ManthokaWaterfall/800/400" },
  { name: "Askole Village", lat: 35.6667, lng: 75.8167, category: "mountain", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "June to August", description: "Askole is the last village before the Baltoro Glacier and the starting point for trekking to K2 base camp and Concordia. This remote Balti village at 3,000m is the last point of human habitation before one of the world's most remote mountain fastnesses.", history: "Askole has been the traditional jumping-off point for Karakoram expeditions since the late 19th century. The village's people have served as porters and guides for over 130 years, developing an extraordinary relationship with the mountaineering world.", image: "https://picsum.photos/seed/Askole/800/400" },
  { name: "Gojal Valley (Upper Hunza)", lat: 36.5500, lng: 74.7500, category: "valley", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "April to October", description: "The northern section of Hunza Valley inhabited by the Wakhi people, extending from Attabad Lake to Khunjerab Pass. Offers extraordinary mountain scenery with views of Passu Cones, Tupopdan, and other Karakoram peaks. The Wakhi culture with its unique language makes Gojal culturally distinctive.", history: "Gojal has been inhabited by the Wakhi people for thousands of years, an Iranian-speaking people historically associated with the Wakhan Corridor. They converted to Ismaili Islam in the 19th century under the Aga Khan's influence.", image: "https://picsum.photos/seed/GojalValley/800/400" },
  { name: "Bagrote Valley", lat: 35.9833, lng: 74.4667, category: "valley", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "June to September", description: "A beautiful side valley near Gilgit with traditional Shina-speaking villages, fruit orchards, and access to challenging mountaineering routes. Trek up to high alpine meadows with views of surrounding Karakoram peaks. Known for high-quality apricots and cherries.", history: "Bagrote Valley has been part of the Gilgit region for centuries with its people maintaining traditional lifestyles. The valley's residents converted to Islam several centuries ago but maintain unique customs blending local Shina culture with Islamic practice.", image: "https://picsum.photos/seed/BagroteValley/800/400" },
  { name: "Ishkoman Valley", lat: 36.5833, lng: 73.8333, category: "valley", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "May to October", description: "A remote and beautiful valley in eastern Ghizer district offering spectacular mountain scenery and gateway to the Karakoram mountains. Inhabited by Ismaili Muslims who maintain warm hospitality. The upper reaches offer excellent trekking into rarely visited alpine areas.", history: "Ishkoman was historically controlled by a local raja who acknowledged the Mehtar of Chitral's suzerainty. British political agents monitored its passes carefully for Russian influence during the Great Game.", image: "https://picsum.photos/seed/IshkomanValley/800/400" },
  { name: "Minapin Glacier", lat: 36.1283, lng: 74.6667, category: "mountain", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "June to October", description: "A stunning glacier near Minapin village in Hunza, accessible by a relatively short trek from the Karakoram Highway. Provides dramatic close-up views of Diran Peak (7,266m) and Rakaposhi. The trekking path through orchards and scrub before reaching the glacier snout is beautiful.", history: "Minapin Glacier has been the subject of glaciological research documenting changes in Karakoram glaciers. The village was historically known for high-quality apricots traded along the Silk Road.", image: "https://picsum.photos/seed/MinapinGlacier/800/400" },
  { name: "Shigar River Valley", lat: 35.5200, lng: 75.7667, category: "valley", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "May to October", description: "Connecting the Baltoro Glacier area with Skardu, the Shigar River Valley offers dramatic scenery of barren mountains with the turquoise river rushing through. Beautiful poplar-lined villages and traditional Balti architecture complete the picture.", history: "Shigar Valley was an important route connecting the high mountain areas of Baltistan with the Indus main valley at Skardu. The Shigar River drains the Baltoro and Biafo glaciers carrying a distinctive milky blue color from glacial silt.", image: "https://picsum.photos/seed/ShigarRiver/800/400" },

  // ═══════════════════════════════════════════
  // KHYBER PAKHTUNKHWA (KPK)
  // ═══════════════════════════════════════════

  { name: "Swat Valley", lat: 35.2227, lng: 72.4258, category: "valley", province: "KPK", rating: 4.8, bestTime: "March to November", description: "Often called the 'Switzerland of Pakistan', Swat is one of the most beautiful valleys in Asia with lush green meadows, dense forests, gushing rivers, and snow-capped peaks. The Swat River flows past ancient Buddhist ruins and traditional villages. Ideal for trekking, fishing, and cultural exploration.", history: "Swat has South Asia's richest prehistoric heritage. It was part of the ancient Gandhara civilization and an important Buddhist center for over a millennium. Alexander the Great passed through in 327 BC. In modern times Swat was an independent princely state until 1969.", image: "https://picsum.photos/seed/SwatValley/800/400" },
  { name: "Kalam", lat: 35.4926, lng: 72.5855, category: "valley", province: "KPK", rating: 4.7, bestTime: "May to October", description: "A small valley town in Upper Swat surrounded by dense pine forests and towering mountains, with the Swat River rushing through it. Serves as base for exploring alpine areas including Mahodand Lake and Ushu Forest. The green meadows and cool climate make it a favorite retreat.", history: "Kalam was historically a remote area inhabited by the Torwali-speaking people who maintained distinct culture and traditions for centuries. Road development in the 1970s opened the area to tourism and transformed it from an agricultural community to a tourist hub.", image: "https://picsum.photos/seed/Kalam/800/400" },
  { name: "Mahodand Lake", lat: 35.7276, lng: 72.6014, category: "lake", province: "KPK", rating: 4.8, bestTime: "July to September", description: "A high-altitude alpine lake near Kalam in Swat at 2,868m. The deep turquoise lake surrounded by snow-capped peaks and green meadows is one of the most beautiful lakes in KPK. Trout fishing and horse riding are popular activities here.", history: "Mahodand means 'Flat Land Lake' in the local Pashto/Torwali language. The lake was a traditional summer grazing area for nomadic communities for centuries. It became widely known only in the 1990s when tourism in Swat expanded significantly.", image: "https://picsum.photos/seed/MahodandLake/800/400" },
  { name: "Malam Jabba", lat: 35.3606, lng: 72.5714, category: "mountain", province: "KPK", rating: 4.5, bestTime: "Dec to Mar (skiing), Jun-Oct (trekking)", description: "Pakistan's largest ski resort in Swat at 2,804m. The resort was destroyed during the Taliban insurgency and rebuilt by a Chinese company, reopening in 2018. In summer the area offers excellent hiking trails and cool mountain air.", history: "Developed as a ski resort in the 1980s with Austrian expertise. Burned down by Taliban militants in 2008. The rebuilt resort opened in 2018 as a major investment in Pakistan's tourism sector, symbolizing the return of normalcy to Swat.", image: "https://picsum.photos/seed/MalamJabba/800/400" },
  { name: "Ushu Forest", lat: 35.4821, lng: 72.5840, category: "wildlife", province: "KPK", rating: 4.6, bestTime: "April to October", description: "A spectacular dense pine and cedar forest along the banks of the Ushu River near Kalam. Home to diverse wildlife; walking through the towering trees with the sound of the rushing river creates a magical atmosphere. The Ushu River offers excellent trout fishing.", history: "Ushu Forest is one of the largest contiguous temperate forests in Pakistan, important for the watershed of the Swat River. The forest has been managed by local communities for generations with traditional rights to timber and grazing.", image: "https://picsum.photos/seed/UshuForest/800/400" },
  { name: "Kumrat Valley", lat: 35.3167, lng: 71.8833, category: "valley", province: "KPK", rating: 4.8, bestTime: "June to October", description: "One of Pakistan's most pristine and beautiful valleys in Upper Dir, with dense forests, crystal-clear rivers, and lush alpine meadows. Compared to Kalam and Swat for its beauty, Kumrat has become increasingly popular with domestic tourists. The Panjkora River rushes through fed by glacial streams.", history: "Kumrat Valley is part of Dir district historically ruled by the Nawab of Dir. The valley's relative inaccessibility preserved its natural character for centuries. Road construction in the 2000s opened the valley to tourism.", image: "https://picsum.photos/seed/KumratValley/800/400" },
  { name: "Jahaz Banda", lat: 35.3500, lng: 72.0000, category: "valley", province: "KPK", rating: 4.7, bestTime: "July to September", description: "An alpine meadow in Kumrat Valley at about 3,100m, shaped like an aircraft (Jahaz means aircraft in Urdu) when viewed from above. The vast flat meadow surrounded by pine forests and snow-capped peaks is an extraordinary camping destination. Wildflowers carpet the meadow in July.", history: "Jahaz Banda has been traditionally used as summer pasture by Gujar and Kohistani nomadic communities. The airplane shape and name became notable only when drone photography became common.", image: "https://picsum.photos/seed/JahazBanda/800/400" },
  { name: "Katora Lake", lat: 35.4500, lng: 72.0500, category: "lake", province: "KPK", rating: 4.8, bestTime: "July to August", description: "A stunningly beautiful high-altitude glacial lake above Kumrat Valley at around 3,600m. The name means 'bowl' in Urdu, perfectly describing the lake's shape nestled in a natural bowl of glaciated rock. The pristine blue waters surrounded by snow and rocky peaks make it one of the most photogenic lakes in Pakistan.", history: "Katora Lake was known to local communities but gained wider fame only in the 2010s when social media spread images of its extraordinary beauty. The challenging access continues to limit visitor numbers, preserving its natural environment.", image: "https://picsum.photos/seed/KatoraLake/800/400" },
  { name: "Chitral City", lat: 35.8500, lng: 71.7833, category: "city", province: "KPK", rating: 4.3, bestTime: "May to October", description: "The main town of Chitral district, a remote but culturally rich area in the Hindu Kush near the Afghan border. Gateway to the Kalash Valley, the town offers a fascinating mix of Kho, Kalash, and Persian cultures. The Chitral Fort and bazaar are historically significant.", history: "Chitral was the capital of the princely state of Chitral, ruled by the Mehtar for centuries. The famous Siege of Chitral in 1895 was a significant event in the Great Game between Britain and Russia. Chitral acceded to Pakistan in 1947.", image: "https://picsum.photos/seed/ChitralCity/800/400" },
  { name: "Kalash Valley", lat: 35.7000, lng: 71.6000, category: "valley", province: "KPK", rating: 4.9, bestTime: "May to October", description: "Home to the Kalash people, an ancient non-Muslim minority living in three valleys. The Kalash maintain a unique pre-Islamic polytheistic religion, culture, and language that has survived for over 3,000 years. Their colorful festivals, traditional clothing, and distinctive wooden temples make this one of the most culturally unique places in the world.", history: "The Kalash claim descent from Alexander the Great's soldiers, though studies suggest they are an ancient indigenous people with pre-Aryan roots. They practiced a polytheistic religion similar to ancient Greek and Vedic pantheons. A population of 3,000-4,000 Kalash has maintained their ancestral tradition for millennia.", image: "https://picsum.photos/seed/KalashValley/800/400" },
  { name: "Bumburet Valley (Kalash)", lat: 35.7083, lng: 71.6750, category: "valley", province: "KPK", rating: 4.9, bestTime: "May to October", description: "The largest and most visited of the three Kalash valleys. Known for Kalash settlements with distinctive wooden architecture, flowing rivers, walnut orchards, and grape vineyards. The major Kalash festivals of Chilam Joshi, Uchau, and Choimos are celebrated here.", history: "Bumburet Valley has been the heartland of the Kalash civilization since ancient times. While neighboring valleys gradually saw conversion to Islam, Bumburet has maintained the highest concentration of Kalash people practicing their traditional religion. Grape and walnut cultivation here is centuries old.", image: "https://picsum.photos/seed/BumburetValley/800/400" },
  { name: "Broghil Valley", lat: 36.8500, lng: 73.2833, category: "valley", province: "KPK", rating: 4.7, bestTime: "July to September", description: "One of the most remote and spectacular valleys in Pakistan at around 3,800m near the Afghan Wakhan Corridor border. The vast open plateau is a summer pasture for Wakhi nomads. The Karambar Lake at the head of the valley is one of Pakistan's most remote and beautiful alpine lakes.", history: "Broghil Valley has been used as a summer migration route between Chitral and the Wakhan Corridor by Wakhi nomads for centuries. The British established a fort here in the late 19th century as part of the Great Game frontier strategy.", image: "https://picsum.photos/seed/BroghilValley/800/400" },
  { name: "Karambar Lake", lat: 36.9833, lng: 73.5333, category: "lake", province: "KPK", rating: 4.9, bestTime: "July to September", description: "Said to be the highest navigable lake in the world at 4,272m, located near the Afghan border. This remote lake at the junction of the Hindu Kush and Karakoram ranges offers an extraordinary alpine landscape. The deep blue-green waters surrounded by high peaks and glaciers is one of the most breathtaking sights in Pakistan.", history: "Local Wakhi nomads have used the area around the lake as summer pasture for centuries, and the lake is considered sacred in local traditions. It was little documented until the 21st century.", image: "https://picsum.photos/seed/KarambarLake/800/400" },
  { name: "Peshawar", lat: 34.0151, lng: 71.5249, category: "city", province: "KPK", rating: 4.3, bestTime: "October to March", description: "One of the oldest cities in South Asia and the capital of KPK, situated at the western gateway of the Khyber Pass. A living museum of Central Asian, Mughal, and British colonial architecture. The vibrant Qissa Khwani Bazaar is famous for its food, culture, and unique blend of Pashto and Persian traditions.", history: "Peshawar has been inhabited for at least 2,000 years and was an important Gandharan city and capital of the Kushan Empire. Successively ruled by Greeks, Parthians, Kushans, Sassanids, and later Muslim conquerors. Emperor Akbar's grandson passed through on campaign to Central Asia.", image: "https://picsum.photos/seed/Peshawar/800/400" },
  { name: "Qissa Khwani Bazaar", lat: 34.0042, lng: 71.5567, category: "historical", province: "KPK", rating: 4.5, bestTime: "October to March", description: "The Storytellers' Bazaar, once known as the 'Piccadilly of Central Asia.' Historically a gathering place for caravanners and storytellers from across Asia. Today famous for Peshwari food, chapli kebabs, and traditional crafts.", history: "Professional storytellers (Qissa Khwans) entertained caravanners throughout the night as they rested before continuing their journeys. In 1930 the bazaar witnessed a notorious massacre by British troops. The market has been at the center of Peshawar's civic life for many centuries.", image: "https://picsum.photos/seed/QissaKhwani/800/400" },
  { name: "Khyber Pass", lat: 34.0983, lng: 71.1264, category: "historical", province: "KPK", rating: 4.5, bestTime: "October to April", description: "One of the most historically important mountain passes in the world, connecting Pakistan's KPK with Afghanistan. This narrow mountain pass has been used by conquerors, traders, and travelers for thousands of years. The dramatic landscape of steep cliffs and narrow gorges is impressive even today.", history: "The Khyber Pass has been the gateway through which history's greatest conquerors entered South Asia: Darius I in 500 BC, Alexander in 327 BC, Mahmud of Ghazni in the 11th century, Timur in the 14th century, Babur in the 16th century. Of vital strategic importance during the Great Game.", image: "https://picsum.photos/seed/KhyberPass/800/400" },
  { name: "Bala Hisar Fort Peshawar", lat: 34.0092, lng: 71.5467, category: "historical", province: "KPK", rating: 4.4, bestTime: "October to April", description: "A historic hilltop fortress overlooking Peshawar that has served as the stronghold of every major power ruling the city. Currently the headquarters of the Frontier Corps, the fort has an imposing presence with massive walls and towers commanding views over the Peshawar Valley.", history: "The fort's origins are ancient, with structures having been built on this hilltop for over 2,000 years. The current structure dates primarily from the Sikh period under Hari Singh Nalwa. It was expanded during the British period and has served as a military headquarters since.", image: "https://picsum.photos/seed/BalaHisarFort/800/400" },
  { name: "Mahabat Khan Mosque Peshawar", lat: 34.0083, lng: 71.5614, category: "historical", province: "KPK", rating: 4.5, bestTime: "October to April", description: "The most beautiful mosque in Peshawar, built during the Mughal period and named after a governor of the city. The painted façade decorated with intricate floral designs in soft colors is unique in Pakistan. The three marble domes and two minarets create an elegant silhouette over the bazaar.", history: "Built in the early 17th century during the reign of Emperor Jahangir or Shah Jahan. The distinctive painted decoration was added during the Sikh period. During the Sikh occupation the mosque's minarets were used for hanging offenders.", image: "https://picsum.photos/seed/MahabatKhanMosque/800/400" },
  { name: "Peshawar Museum", lat: 34.0196, lng: 71.5584, category: "historical", province: "KPK", rating: 4.7, bestTime: "October to April", description: "One of the finest museums in Pakistan, housing the world's most comprehensive collection of Gandhara Buddhist sculpture and art. Galleries display exquisite carved stone panels, Buddha statues, and Gandhara art spanning from the 1st century BCE to the 7th century CE.", history: "Established in 1906 during the British colonial period as the Edwardes Hall Museum. The collection grew rapidly due to archaeological excavations across the NWFP. It is one of the most culturally significant museums for understanding the Buddhist civilization of the Gandhara region.", image: "https://picsum.photos/seed/PeshawarMuseum/800/400" },
  { name: "Kaghan Valley", lat: 34.6000, lng: 73.5000, category: "valley", province: "KPK", rating: 4.8, bestTime: "May to October", description: "A picture-perfect mountain valley in Mansehra district, one of Pakistan's most beloved tourist destinations. Stretches northward from Balakot to Babusar Pass with increasing alpine scenery. The Kunhar River rushes through the valley past meadows, waterfalls, and charming villages.", history: "Kaghan Valley has been inhabited since ancient times. The valley's name may derive from the 'Kagan' or 'Kaghan' title of ancient Huns who ruled the area. The British incorporated it into Hazara district and developed it as a summer retreat.", image: "https://picsum.photos/seed/KaghanValley/800/400" },
  { name: "Lake Saif ul Malook", lat: 34.8840, lng: 73.6887, category: "lake", province: "KPK", rating: 4.9, bestTime: "June to September", description: "One of Pakistan's most stunning alpine lakes at 3,224m, surrounded by peaks including Malika Parbat (5,291m). The deep turquoise lake with crystal-clear waters reflecting snow-capped peaks is one of the most beautiful lakes in South Asia. Associated with a famous Punjabi love poem by Mian Muhammad Bakhsh.", history: "The lake is central to a famous Punjabi romantic legend about Prince Saif ul Malook who fell in love with fairy princess Badri ul Jamala here. The legend was immortalized by Sufi poet Mian Muhammad Bakhsh in the 19th century.", image: "https://picsum.photos/seed/SaifulMalookLake/800/400" },
  { name: "Naran", lat: 34.9042, lng: 73.6547, category: "mountain", province: "KPK", rating: 4.6, bestTime: "June to September", description: "A popular hill town in the Kaghan Valley at 2,409m serving as the main base for exploring the region including Lake Saif ul Malook and Babusar Pass. The Kunhar River flows through surrounded by high mountain peaks. Hotels, restaurants, and jeep services make it the tourism hub.", history: "Naran was a small agricultural village until the 1970s when improved road access transformed it into a tourist centre. The town experienced rapid growth as domestic tourism expanded dramatically in Pakistan in the early 21st century.", image: "https://picsum.photos/seed/NaranValley/800/400" },
  { name: "Babusar Pass", lat: 35.1900, lng: 73.8900, category: "mountain", province: "KPK", rating: 4.7, bestTime: "July to September", description: "Babusar Pass at 4,173m is the gateway between Kaghan Valley and Gilgit-Baltistan. Offers spectacular views of surrounding peaks and serves as an important transit point for travelers. Snow typically covers the pass for most of the year, opening only in late June.", history: "Babusar Pass has historically served as a seasonal trade and migration route used by Gujar nomads who migrated with livestock between summer and winter pastures. It became a popular tourist route in the late 20th century.", image: "https://picsum.photos/seed/BabusarPass/800/400" },
  { name: "Lulusar Lake", lat: 34.9943, lng: 73.8500, category: "lake", province: "KPK", rating: 4.7, bestTime: "July to September", description: "A high-altitude alpine lake near Babusar Pass at 3,411m. The large lake with blue-green waters set in a wide grassy basin is one of the most scenic spots in Kaghan Valley. The lake is the source of the Kunhar River flowing all the way to Naran and beyond.", history: "Lulusar Lake is the headwater source of the Kunhar River that gives life to the entire Kaghan Valley. The surrounding grasslands are traditional summer pasture for Gujar nomads.", image: "https://picsum.photos/seed/LulusarLake/800/400" },
  { name: "Dudipatsar Lake", lat: 35.0500, lng: 73.7333, category: "lake", province: "KPK", rating: 4.9, bestTime: "July to August", description: "Dudipatsar means 'Queen of Lakes' and is considered one of the most beautiful alpine lakes in Pakistan at 4,058m. The remote lake with its deep blue-green waters requires a full day's trek to reach. Accessible from Naran via a challenging but rewarding trail through alpine meadows.", history: "Dudipatsar Lake was little known outside local communities until Pakistani mountaineers and hikers began exploring the area. The lake remains one of the less-visited major attractions due to challenging access, which has helped preserve its pristine character.", image: "https://picsum.photos/seed/DudipatarLake/800/400" },
  { name: "Shogran Meadow", lat: 34.7063, lng: 73.5136, category: "mountain", province: "KPK", rating: 4.6, bestTime: "May to October", description: "A beautiful hilltop meadow in the Kaghan Valley at 2,362m, accessible by road or scenic cable car. From the meadow there are magnificent views of surrounding peaks and forested hillsides. Covered with wildflowers in spring and early summer.", history: "Shogran was a traditional summer grazing ground before being developed as a tourist destination in the early 21st century. The cable car installation transformed it into a significant domestic tourism destination.", image: "https://picsum.photos/seed/Shogran/800/400" },
  { name: "Nathiagali", lat: 34.0727, lng: 73.3816, category: "mountain", province: "KPK", rating: 4.5, bestTime: "April to October", description: "One of the most popular hill stations in Pakistan, part of the Galyat region. Sits at 2,520m surrounded by dense pine forests with spectacular mountain views. Several hiking trails including the famous Miranjani summit trail start from Nathiagali.", history: "Developed as a hill station by the British colonial administration in the 19th century as a summer retreat. The British built bungalows, churches, and a governor's lodge here. The area became popular with Lahore's elite during the colonial era.", image: "https://picsum.photos/seed/Nathiagali/800/400" },
  { name: "Ayubia National Park", lat: 34.0594, lng: 73.3992, category: "wildlife", province: "KPK", rating: 4.5, bestTime: "April to October", description: "Covers 3,312 hectares of mixed conifer and broad-leaved forest in the Galyat region. Contains several picnic spots, hiking trails, and a chair lift connecting Dungagali to Ayubia. Wildlife includes leopards, barking deer, and numerous bird species.", history: "Established in 1984 to protect the temperate forests of the Galyat region from deforestation. Named after former Pakistani President Ayub Khan who had a fondness for the Galyat area. Conservation efforts have helped recover populations of native wildlife.", image: "https://picsum.photos/seed/AyubiaNationalPark/800/400" },
  { name: "Dir Valley", lat: 35.2070, lng: 71.8786, category: "valley", province: "KPK", rating: 4.4, bestTime: "April to October", description: "Encompasses both Upper and Lower Dir districts in western KPK, known for beautiful forested mountains, rivers, and traditional Pashtun culture. Offers several trekking opportunities and is the gateway to Kumrat and other isolated alpine areas.", history: "Dir was an independent princely state under the Nawabs of Dir until 1969. The area was significant during the Afghan jihad in the 1980s as a transit point and later saw Taliban activity in the 2000s before being cleared by the Pakistani military.", image: "https://picsum.photos/seed/DirValley/800/400" },
  { name: "Chitral Gol National Park", lat: 35.9500, lng: 71.7333, category: "wildlife", province: "KPK", rating: 4.6, bestTime: "June to October", description: "The only protection area for the Markhor, Pakistan's national animal, in Chitral district. Offers remarkable wildlife watching opportunities including Markhor, snow leopard, and mountain birds. The dramatic mountain scenery with glaciated peaks adds to its appeal.", history: "Established in 1984. Originally the royal hunting ground of the Mehtar of Chitral, which paradoxically helped preserve the Markhor population. The conservation of Markhor at Chitral Gol is considered one of Pakistan's greatest wildlife conservation successes.", image: "https://picsum.photos/seed/ChitralGolPark/800/400" },
  { name: "Mattiltan Valley", lat: 35.7000, lng: 72.5500, category: "valley", province: "KPK", rating: 4.7, bestTime: "June to September", description: "A beautiful alpine valley above Kalam in Upper Swat, accessible by a scenic jeep track. Contains magnificent forests, rushing streams, and access to high alpine meadows. The Kundol Lake trek starts from Matiltan and is one of the finest day treks in KPK.", history: "Matiltan Valley was traditionally inhabited by the Torwali-speaking people who maintained cattle and sheep in the valley's rich pastures. Tourism development since the 1990s has brought significant economic change to the valley's communities.", image: "https://picsum.photos/seed/MatilatanValley/800/400" },
  { name: "Kundol Lake", lat: 35.7500, lng: 72.5400, category: "lake", province: "KPK", rating: 4.8, bestTime: "July to August", description: "A stunningly beautiful high-altitude lake above Matiltan Valley in Upper Swat at around 3,500m, reachable by a challenging but spectacular trek. The glacial cirque lake with crystal-clear waters and peaks towering above is one of the most photogenic destinations in KPK.", history: "Kundol Lake was known to local communities as a summer pasture area but came to wider attention only when trekking tourism expanded in Swat in the 2000s. The difficult access contributed to its relatively pristine state.", image: "https://picsum.photos/seed/KundolLake/800/400" },
  { name: "Gabral Valley", lat: 35.5167, lng: 72.4833, category: "valley", province: "KPK", rating: 4.6, bestTime: "May to October", description: "A side valley branching off Kalam Valley with dense forests, gushing streams, and scenic meadows. Relatively less visited than Kalam and Mahodand, offering a more peaceful mountain experience. Several waterfalls cascade through the forests.", history: "Gabral Valley is inhabited by Torwali-speaking communities who traditionally practiced a mixed economy of farming, herding, and collecting forest produce. The valley was part of Swat State and maintains relatively traditional lifestyles.", image: "https://picsum.photos/seed/GabralValley/800/400" },
  { name: "Marghuzar White Palace (Swat)", lat: 34.9300, lng: 72.3000, category: "historical", province: "KPK", rating: 4.6, bestTime: "April to October", description: "Marghuzar Valley contains the White Palace (Sufaid Mahal) built by the Wali of Swat in the 1940s. The Italian-style white marble palace set against green hills and a clear stream is now a government rest house. The surrounding meadows and forests are ideal for nature walks.", history: "Built by Miangul Abdul Haq Jahanzeb, the Wali of Swat, who ruled the princely state from 1949-69. The palace combined European architectural elements with local Swati culture. The Wali was famous for progressive governance, building schools, hospitals, and roads.", image: "https://picsum.photos/seed/WhitePalaceSwat/800/400" },
  { name: "Saidu Sharif", lat: 34.7426, lng: 72.3570, category: "historical", province: "KPK", rating: 4.3, bestTime: "April to October", description: "Capital of Swat district, containing important museums with Buddhist era Gandharan sculptures and artifacts. The Swat Museum near here is one of Pakistan's best regional museums with remarkable Gandharan art. The area itself has numerous Buddhist stupa remains.", history: "Saidu Sharif is named after the Akhund of Swat, Saidu Baba, a revered religious leader of the 19th century. It was the seat of the Wali of Swat State and grew as administrative center when the Swat state was formally established in 1917.", image: "https://picsum.photos/seed/SaiduSharif/800/400" },
  { name: "Bahrain, Swat", lat: 35.2000, lng: 72.5530, category: "valley", province: "KPK", rating: 4.5, bestTime: "April to October", description: "A scenic small town in Swat Valley at the confluence of the Swat and Daral rivers. A popular base for trekking into surrounding mountains and valleys. The bustling bazaar along the river is colorful and the surrounding mountain scenery is spectacular.", history: "Bahrain has been an important market town on the trade route through Swat since medieval times. Its location at the confluence of major rivers made it a natural stopping point for merchants and travelers.", image: "https://picsum.photos/seed/BahrainSwat/800/400" },
  { name: "Abbottabad", lat: 34.1558, lng: 73.2194, category: "city", province: "KPK", rating: 4.1, bestTime: "March to November", description: "A pleasant hill town in the Hazara region, famous for its cool climate, military academy, and natural beauty. Surrounded by pine-covered hills with views of the surrounding mountains. Gained international fame in 2011 as the location where Osama bin Laden was found.", history: "Founded in 1853 by Major James Abbott as a colonial administrative center for the Hazara district. The town was named after Abbott himself and became the headquarters of Pakistan's famous Pakistan Military Academy at Kakul.", image: "https://picsum.photos/seed/Abbottabad/800/400" },
  { name: "Balakot", lat: 34.5511, lng: 73.3512, category: "city", province: "KPK", rating: 4.1, bestTime: "March to November", description: "A town at the entrance to the Kaghan Valley on the banks of the Kunhar River. Balakot serves as the gateway to Kaghan and is famous as the site of a historic battle and the starting point for Kaghan valley tourism.", history: "Balakot was the site of the famous Battle of Balakot (1831) in which the Islamic reformist movement of Syed Ahmad Barelvi fought against Sikh forces. The battle is considered a significant event in the development of Islamic reform movements in South Asia.", image: "https://picsum.photos/seed/Balakot/800/400" },
  { name: "Batakundi", lat: 34.8550, lng: 73.5900, category: "mountain", province: "KPK", rating: 4.4, bestTime: "June to September", description: "A scenic mountain community in the Kaghan Valley above Naran. An excellent base for trekking with magnificent mountain views. The road beyond Batakundi leads to Babusar Pass and is one of the most spectacular drives in Pakistan.", history: "Batakundi was traditionally a Gujar nomadic community area, serving as a transit point for pastoral communities moving between lower and upper Kaghan Valley. The town developed as a waypoint for travelers and trekkers.", image: "https://picsum.photos/seed/Batakundi/800/400" },
  { name: "Reshun Valley (Chitral)", lat: 36.1000, lng: 71.9833, category: "valley", province: "KPK", rating: 4.4, bestTime: "May to October", description: "A beautiful valley on the road between Chitral and Gilgit via Shandur, known for lush green meadows and traditional Kho villages. The Mastuj River flows through and the surrounding mountains offer excellent trekking. Distinct Kho culture pervades the area.", history: "Reshun was the site of a significant event in the 1895 Chitral Campaign when a British relief force was ambushed by Chitrali forces. It connects the Chitral heartland with the Yasin Valley and has been an important route for centuries.", image: "https://picsum.photos/seed/ReshunValley/800/400" },
  { name: "Mastuj (Upper Chitral)", lat: 36.2833, lng: 72.5167, category: "valley", province: "KPK", rating: 4.4, bestTime: "May to October", description: "The main town in upper Chitral district, serving as the junction for roads to Shandur Pass and Broghil Valley. A distinctive frontier community between the Kho, Wakhi, and Pathan cultural worlds. The surrounding landscapes are extraordinarily scenic.", history: "Mastuj was the seat of a sub-chieftain of Chitral and an important strategic point in the upper Chitral territories. The 1895 Siege of Chitral included a detachment being besieged at Mastuj Fort.", image: "https://picsum.photos/seed/Mastuj/800/400" },
  { name: "Taxila", lat: 33.7467, lng: 72.8333, category: "historical", province: "Punjab", rating: 4.7, bestTime: "October to March", description: "One of the most important archaeological sites in Asia, containing ruins of an ancient city that was a major center of Buddhist learning, culture, and commerce. The site encompasses multiple archaeological zones including the ancient city of Sirkap, Buddhist monasteries, and the famous Taxila Museum. A UNESCO World Heritage Site.", history: "Taxila (ancient Takshashila) was one of the great cities of the ancient world, mentioned in both the Mahabharata and Buddhist texts. Chandragupta Maurya and Chanakya are said to have studied here. It was conquered by Alexander the Great in 326 BC.", image: "https://picsum.photos/seed/TaxilaRuins/800/400" },
  { name: "Jaulian Monastery Taxila", lat: 33.7500, lng: 72.8667, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "A Buddhist monastery and stupa complex at Taxila dating from the 4th-5th centuries CE. Contains over 21 votive stupas decorated with geometric plasterwork figures of Buddhas and Bodhisattvas. One of the best preserved Buddhist monastic complexes in Pakistan.", history: "Jaulian was a major Buddhist monastery during the Kushan period, destroyed in the 5th century CE during Hephthalite invasions. Excavated by John Marshall of the Archaeological Survey of India in the 1910s.", image: "https://picsum.photos/seed/JaulianMonastery/800/400" },
  { name: "Sirkap (Taxila)", lat: 33.7611, lng: 72.8486, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "The second major ancient city at Taxila, a planned Hellenistic-influenced city built by the Bactrian Greeks around 180 BCE and occupied until the Kushan period. The city's street plan follows a grid system inherited from Hellenistic city planning.", history: "Sirkap was founded by the Greco-Bactrian king Demetrius I around 180 BCE. Shows characteristic Hellenistic planning with a main avenue and side streets in a grid pattern. Successively inhabited by Greeks, Indo-Scythians, Indo-Parthians, and Kushans.", image: "https://picsum.photos/seed/SirkapTaxila/800/400" },
  { name: "Margalla Hills", lat: 33.7607, lng: 73.0656, category: "mountain", province: "Islamabad", rating: 4.5, bestTime: "October to April", description: "A range of low mountains serving as backdrop to Islamabad, protected as the Margalla Hills National Park. The hills offer numerous hiking trails, picnic spots, and viewpoints above the capital. Wildlife including leopards, wild boars, and monkeys inhabit the forested hills.", history: "The Margalla Hills are an extension of the outer Himalayas (Siwalik Hills). When Islamabad was planned in the 1960s, the Margalla Hills were designated as a protected area to serve as the city's 'green lung.'", image: "https://picsum.photos/seed/MargallaHills/800/400" },

  // ═══════════════════════════════════════════
  // ISLAMABAD & RAWALPINDI
  // ═══════════════════════════════════════════

  { name: "Faisal Mosque", lat: 33.7294, lng: 73.0379, category: "religious", province: "Islamabad", rating: 4.8, bestTime: "All year", description: "One of the largest mosques in the world and an iconic symbol of Pakistan. Designed by Turkish architect Vedat Dalokay, the tent-shaped main hall surrounded by four slim minarets is a unique and stunning architectural statement set against the Margalla Hills.", history: "Built between 1976-1986, funded by Saudi King Faisal bin Abdul Aziz after whom it is named. Turkish architect Vedat Dalokay won the international design competition in 1969 with his modernist design inspired by a Bedouin tent. At its completion it was the largest mosque in the world.", image: "https://picsum.photos/seed/FaisalMosque/800/400" },
  { name: "Pakistan Monument", lat: 33.6938, lng: 73.0686, category: "historical", province: "Islamabad", rating: 4.6, bestTime: "All year", description: "A national monument representing Pakistan's four provinces and three territories, shaped like a blooming flower with four petals. The surrounding museum and gardens make it a major cultural attraction in Islamabad.", history: "Inaugurated on March 23, 2007, on the 67th anniversary of the Lahore Resolution. The Heritage Museum at the base depicts the history of the Pakistan Movement and the diverse cultures of the country's regions.", image: "https://picsum.photos/seed/PakistanMonument/800/400" },
  { name: "Daman-e-Koh", lat: 33.7446, lng: 73.0496, category: "mountain", province: "Islamabad", rating: 4.5, bestTime: "October to April", description: "A hilltop garden and viewpoint in the Margalla Hills above Islamabad offering one of the best views of the capital city. The name means 'Skirt of the mountain' in Urdu. During sunset the panoramic view of the planned capital spreading below is spectacular.", history: "Daman-e-Koh was developed as a viewpoint when Islamabad was being built in the 1960s. Over the decades it has become one of Islamabad's most popular recreation spots.", image: "https://picsum.photos/seed/DamanEKoh/800/400" },
  { name: "Pir Sohawa", lat: 33.7555, lng: 73.0607, category: "mountain", province: "Islamabad", rating: 4.4, bestTime: "October to April", description: "A scenic hilltop above Islamabad at 1,600m in the Margalla Hills, accessible by a winding road through dense forest. Several restaurants at the top offer spectacular views over Islamabad and surrounding hills. Sunrise and sunset views are spectacular.", history: "The hill was named after a local saint (Pir) buried here. The road to Pir Sohawa was developed in the 1970s as part of Islamabad's tourism infrastructure and has become one of the most popular evening destinations for residents.", image: "https://picsum.photos/seed/PirSohawa/800/400" },
  { name: "Lake View Park", lat: 33.6956, lng: 73.1207, category: "lake", province: "Islamabad", rating: 4.3, bestTime: "October to April", description: "An attractive park in Islamabad designed around a serene artificial lake with beautifully manicured gardens. Features boating facilities, a plant conservatory, and recreational areas. Especially beautiful during spring when garden flowers bloom.", history: "Developed in the late 1990s as part of Islamabad's planned recreational infrastructure. The Capital Development Authority created the park as one of several planned green spaces intended to give Islamabad's residents access to nature within the city.", image: "https://picsum.photos/seed/LakeViewPark/800/400" },
  { name: "Margalla Hills National Park", lat: 33.7667, lng: 73.0667, category: "wildlife", province: "Islamabad", rating: 4.5, bestTime: "October to April", description: "Covers 17,386 hectares of hills overlooking Islamabad with over 600 plant species, 250 bird species, and 38 mammal species including leopard and barking deer. Numerous clearly marked trails cater to hikers of all levels.", history: "Established in 1980 to protect the forests overlooking the new capital. The hills have been important as a boundary region since ancient times, forming the last extension of the Himalayas before the Indus plain.", image: "https://picsum.photos/seed/MargallaPark/800/400" },
  { name: "Rawalpindi", lat: 33.5651, lng: 73.0169, category: "city", province: "Punjab", rating: 4.1, bestTime: "October to March", description: "Pakistan's fourth largest city, twin city of Islamabad, and an important military and commercial center. The historic Saddar Bazaar and Raja Bazaar offer colorful shopping experiences. The city houses Pakistan Army's General Headquarters (GHQ).", history: "Rawalpindi has been inhabited for at least 3,000 years. Developed significantly during the British colonial period as headquarters of the British Indian Army's northern command. Served briefly as capital of Pakistan before Islamabad was constructed in the 1960s.", image: "https://picsum.photos/seed/Rawalpindi/800/400" },
  { name: "Attock Fort", lat: 33.7700, lng: 72.3610, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "A magnificent 16th-century Mughal fortress built by Emperor Akbar at the critical crossing point of the Indus River. The fort's massive walls and bastions overlook the confluence of the Indus and Kabul rivers. It has been in continuous military use since construction.", history: "Built by Emperor Akbar between 1581-83 at the site of an ancient river crossing that controlled access between Punjab and Afghanistan. Whoever controlled this crossing effectively controlled the western gateway into India. The fort has never been successfully stormed.", image: "https://picsum.photos/seed/AttockFort/800/400" },
  { name: "Wah Mughal Garden", lat: 33.7725, lng: 72.7275, category: "historical", province: "Punjab", rating: 4.4, bestTime: "October to March", description: "A Mughal-era garden complex built along the Grand Trunk Road, containing a beautiful bathhouse, pavilions, and water channels laid out in the traditional Mughal chahar-bagh plan. A significant example of Mughal garden culture in the Punjab.", history: "Reportedly built by Emperor Akbar who exclaimed 'Wah!' (Wonderful!) when he saw the location, giving the site its name. The garden was a rest stop on the Grand Trunk Road between Lahore and Kabul used by Mughal emperors on their frequent journeys.", image: "https://picsum.photos/seed/WahMughalGarden/800/400" },
  { name: "Mankiala Stupa", lat: 33.1667, lng: 72.8667, category: "historical", province: "Punjab", rating: 4.3, bestTime: "October to March", description: "A well-preserved Buddhist stupa from the Kushan period (1st-3rd century CE) near Rawalpindi. One of the best-preserved Buddhist monuments in Punjab, the circular brick stupa is evidence of the Buddhist civilization of ancient Punjab.", history: "Associated with a Jataka story in which the historical Buddha sacrificed his flesh to save an eagle pursuing a dove. Visited by Chinese Buddhist pilgrim Xuanzang in the 7th century CE. Excavated by the British in 1830, revealing the internal chamber with relics.", image: "https://picsum.photos/seed/MankialaStupa/800/400" },

  // ═══════════════════════════════════════════
  // PUNJAB
  // ═══════════════════════════════════════════

  { name: "Lahore Fort (Shahi Qila)", lat: 31.5889, lng: 74.3106, category: "historical", province: "Punjab", rating: 4.9, bestTime: "October to March", description: "A magnificent Mughal fortress complex and one of the finest examples of Mughal architecture in the world. Contains beautiful palace buildings, gardens, and galleries of the Mughal era, including the Sheesh Mahal (Mirror Palace). A UNESCO World Heritage Site.", history: "The Lahore Fort has been the seat of power in Lahore for at least a thousand years. Substantially built by Emperor Akbar in the 1560s-70s. Subsequent Mughal emperors all added magnificent structures. Later captured by the Sikh Empire and then by the British. Its 21 distinct monuments tell about 1,000 years of history.", image: "https://picsum.photos/seed/LahoreFort/800/400" },
  { name: "Badshahi Mosque", lat: 31.5889, lng: 74.3105, category: "historical", province: "Punjab", rating: 4.9, bestTime: "October to March", description: "One of the largest mosques in the world and the finest example of Mughal religious architecture. Built in 1673 by Emperor Aurangzeb, its vast courtyard can accommodate 100,000 worshippers. Red sandstone exterior with white marble inlay and four minarets create an iconic silhouette.", history: "Built by Emperor Aurangzeb between 1671-73 AD as the imperial mosque for Lahore. Was the largest mosque in the world for over 300 years. During the Sikh Empire it was used as a garrison and stable. The mosque holds sacred relics of the Prophet Muhammad.", image: "https://picsum.photos/seed/BadshahiMosque/800/400" },
  { name: "Shalimar Gardens", lat: 31.5854, lng: 74.3903, category: "historical", province: "Punjab", rating: 4.7, bestTime: "October to March", description: "Magnificent Mughal gardens laid out in three terraces with hundreds of fountains, reflecting pools, and pavilions. Built by Emperor Shah Jahan in 1641, representing the peak of Mughal garden design. A UNESCO World Heritage Site.", history: "Constructed by Mughal Emperor Shah Jahan in 1641 AD. The name 'Shalimar' comes from the Sanskrit 'Shalimara' meaning 'abode of love.' Built utilizing an elaborate system of water channels and tanks. Shah Jahan often visited the gardens as a symbol of imperial magnificence.", image: "https://picsum.photos/seed/ShalimarGardens/800/400" },
  { name: "Minar-e-Pakistan", lat: 31.5925, lng: 74.3095, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "A tall monument in Lahore marking the site where the Pakistan Resolution was passed on March 23, 1940, demanding a separate nation for Muslims. The 60m tall minaret is a symbol of Pakistan's creation and a major Lahore landmark.", history: "The Lahore Resolution demanding the creation of a separate Muslim state was passed at this site on March 23, 1940. Minar-e-Pakistan was built between 1960-68 to commemorate this momentous occasion. Pakistan celebrates National Day (March 23) with ceremonies at this site.", image: "https://picsum.photos/seed/MinarePakistan/800/400" },
  { name: "Walled City of Lahore", lat: 31.5820, lng: 74.3236, category: "historical", province: "Punjab", rating: 4.8, bestTime: "October to March", description: "A living urban heritage of the Mughal era, enclosed within ancient walls with thirteen historical gates. Densely packed neighborhoods contain mosques, havelis, shrines, and bazaars operating for centuries. The Wazir Khan Mosque within is considered the finest tilework mosque in Pakistan.", history: "The Walled City's current form dates largely from the Mughal period. The thirteen gates (only seven survive) were named after various historical figures or destinations. At its peak under the Mughal Empire it was one of the largest and wealthiest cities in Asia.", image: "https://picsum.photos/seed/WalledCityLahore/800/400" },
  { name: "Wazir Khan Mosque", lat: 31.5808, lng: 74.3264, category: "historical", province: "Punjab", rating: 4.8, bestTime: "October to March", description: "Built in 1634, considered the finest example of Mughal tilework in the world. The mosque's exterior is covered in exquisite kashi-kari (tile mosaic) work in brilliant blue, turquoise, yellow, and white patterns. The interior courtyard's decorative tilework and fresco painting are equally magnificent.", history: "Built under the patronage of Nawab Wazir Khan, governor of Lahore during Emperor Shah Jahan's reign. The mosque took approximately seven years to construct. Master craftsmen from across the Mughal Empire created the exquisite tilework.", image: "https://picsum.photos/seed/WazirKhanMosque/800/400" },
  { name: "Data Darbar", lat: 31.5753, lng: 74.3247, category: "religious", province: "Punjab", rating: 4.7, bestTime: "All year", description: "The shrine of the Sufi saint Hazrat Ali Hujwiri (Data Ganj Bakhsh), patron saint of Lahore. Attracts thousands of devotees daily and is one of the most visited Sufi shrines in South Asia. Thursday night qawwali sessions are especially atmospheric.", history: "Data Ganj Bakhsh was an 11th-century Sufi scholar who settled in Lahore and wrote 'Kashf al-Mahjub,' the first Persian treatise on Sufism. He died around 1072 CE. His shrine has been continuously venerated for nearly 1,000 years.", image: "https://picsum.photos/seed/DataDarbar/800/400" },
  { name: "Lahore Museum", lat: 31.5683, lng: 74.3200, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "One of the best museums in South Asia, housing an extraordinary collection spanning prehistoric to modern Pakistan. Particularly famous for its Gandhara sculpture collection and the statue of the Fasting Siddhartha (Gautama Buddha) considered one of the finest Buddhist sculptures in the world.", history: "Established in 1865 with the current magnificent Victorian Gothic building constructed in 1890. John Lockwood Kipling, father of Rudyard Kipling, was Principal of the Lahore School of Art and curator of the museum from 1875. The Gandhara collection is one of the finest in the world.", image: "https://picsum.photos/seed/LahoreMuseum/800/400" },
  { name: "Jahangir's Tomb (Shahdara)", lat: 31.5533, lng: 74.2797, category: "historical", province: "Punjab", rating: 4.7, bestTime: "October to March", description: "One of the finest Mughal mausoleums in Pakistan. The low, sprawling red sandstone structure with white marble inlay and four corner minarets sits within magnificent gardens. The interior tomb chamber with stunning pietra dura floral work is extraordinarily beautiful.", history: "Emperor Jahangir died in 1627 CE and was buried here across the Ravi River from Lahore per his wishes. His wife Noor Jahan supervised construction of the mausoleum between 1627-37. Sikh ruler Ranjit Singh later removed some marble for his own construction projects.", image: "https://picsum.photos/seed/JahangirTomb/800/400" },
  { name: "Noor Jahan Tomb", lat: 31.5547, lng: 74.2778, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "The Tomb of Empress Noor Jahan stands near the tomb of her husband Emperor Jahangir in Shahdara. The most powerful empress in Mughal history, Noor Jahan built her own tomb during her lifetime. The structure is beautifully decorated with original marble inlay work.", history: "Noor Jahan (1577-1645) was the 20th wife of Emperor Jahangir who wielded extraordinary political power for two decades, effectively co-ruling the Mughal Empire. She was a poet, designer, and businesswoman. She outlived Jahangir by 18 years and was interred in this tomb in 1645.", image: "https://picsum.photos/seed/NoorJahanTomb/800/400" },
  { name: "Anarkali Bazaar", lat: 31.5600, lng: 74.3219, category: "historical", province: "Punjab", rating: 4.5, bestTime: "October to March", description: "One of the oldest and largest bazaars in South Asia, dating back to the Mughal period. Famous for its traditional clothing, embroidered fabrics, jewelry, and food. Named after Anarkali, a legendary court dancer allegedly executed by Emperor Akbar.", history: "The bazaar grew around the tomb of Anarkali, the legendary dancer executed by Mughal Emperor Akbar around 1599 CE for a romance with Prince Salim (later Emperor Jahangir). The bazaar became one of Lahore's primary commercial centers across centuries.", image: "https://picsum.photos/seed/AnarkalizBazaar/800/400" },
  { name: "Wagah Border", lat: 31.6012, lng: 74.5730, category: "historical", province: "Punjab", rating: 4.7, bestTime: "All year", description: "The only road border crossing between Pakistan and India, famous for the daily Beating Retreat ceremony. Soldiers from both sides perform an elaborate flag-lowering ceremony every sunset, attracting thousands of spectators. A fascinating display of military pageantry and nationalistic sentiment.", history: "The Wagah-Attari border was established at partition in 1947 and the flag ceremony has been held since 1959. It has become one of the most unusual tourist attractions in South Asia, combining nationalistic ceremony with a bizarre form of friendly competition.", image: "https://picsum.photos/seed/WagahBorder/800/400" },
  { name: "Rohtas Fort", lat: 32.9676, lng: 73.5899, category: "historical", province: "Punjab", rating: 4.7, bestTime: "October to March", description: "A massive 16th-century fortress with walls stretching over 4 km and enormous gates and bastions. One of the best-preserved early Muslim fortifications in South Asia. A UNESCO World Heritage Site.", history: "Built between 1541-43 by Sher Shah Suri to monitor possible return of Mughal Emperor Humayun. Built in just two years using thousands of laborers. The fort was never actually stormed — its very presence was enough to deter attack.", image: "https://picsum.photos/seed/RohtasFort/800/400" },
  { name: "Khewra Salt Mine", lat: 32.6479, lng: 73.0104, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "The world's second largest salt mine and Pakistan's largest. Inside is a surreal landscape of illuminated salt chambers, an underground mosque, and even a small post office carved from crystalline pink salt. Visitors can experience a train ride through the mine's tunnels.", history: "Said to have been discovered by Alexander the Great's horses in 326 BC. Systematic mining began in the Mughal period. The British expanded operations significantly after 1849. The mine's distinctive pink Himalayan salt became a global commodity in the early 21st century.", image: "https://picsum.photos/seed/KhewraSaltMine/800/400" },
  { name: "Derawar Fort", lat: 28.7694, lng: 71.3345, category: "historical", province: "Punjab", rating: 4.7, bestTime: "October to February", description: "A magnificent desert fortress rising dramatically from the flat Cholistan desert with 40 circular bastions visible from 50 km away. Remains in perfect structural condition. The surrounding Cholistan Desert offers camel safaris and a unique desert landscape.", history: "Built in the 9th century by a Rajput ruler, captured by the Nawabs of Bahawalpur in 1733. The Nawab rebuilt and expanded the fort to its current magnificent form. The Abbasi royal family of Bahawalpur still maintains ownership.", image: "https://picsum.photos/seed/DerawarFort/800/400" },
  { name: "Noor Mahal Bahawalpur", lat: 29.3956, lng: 71.6836, category: "historical", province: "Punjab", rating: 4.5, bestTime: "October to March", description: "A magnificent 19th-century Italianate palace at Bahawalpur, built by Nawab Sadiq Muhammad Khan IV around 1872. The palace's exquisite marble interior and elegant European architecture make it one of the most beautiful heritage buildings in Punjab.", history: "Built by the Nawab of Bahawalpur as a result of the Nawabs' fascination with European architectural styles during the British period. Bahawalpur state was one of the most prosperous princely states in British India due to its fertile cotton-growing lands.", image: "https://picsum.photos/seed/NoorMahal/800/400" },
  { name: "Hiran Minar", lat: 31.7200, lng: 73.9850, category: "historical", province: "Punjab", rating: 4.5, bestTime: "October to March", description: "A Mughal monument built by Emperor Jahangir in memory of his favorite pet deer Mans Raj. The 30-meter minaret stands on the edge of a large water tank surrounded by gardens. An unusual example of Mughal architecture dedicated to a beloved animal.", history: "Built by Emperor Jahangir around 1606 AD in Sheikhupura near his favorite hunting ground. The minaret marks the grave of Jahangir's pet deer Mans Raj who lived for 20 years. The complex was also used as a hunting lodge and pleasure resort.", image: "https://picsum.photos/seed/HiranMinar/800/400" },
  { name: "Multan", lat: 30.1980, lng: 71.4700, category: "city", province: "Punjab", rating: 4.4, bestTime: "October to March", description: "One of Pakistan's oldest cities, known as the 'City of Saints' for its numerous Sufi shrines and the 'City of Silversmiths' for its traditional crafts. Famous for its distinctive blue pottery, embroidery (soosi), and camel skin lamps. The shrines of Bahauddin Zakariya and Shah Rukn-e-Alam dominate the skyline.", history: "Multan is one of the oldest cities in the world possibly founded over 5,000 years ago. Alexander the Great was nearly killed here during his siege in 325 BC. The city later became a major center of Buddhism, then Islam, and a hub of Sufi scholarship for centuries.", image: "https://picsum.photos/seed/Multan/800/400" },
  { name: "Shah Rukn-e-Alam Shrine", lat: 30.2092, lng: 71.4792, category: "religious", province: "Punjab", rating: 4.8, bestTime: "All year", description: "One of the finest examples of Tughluq architecture in South Asia. The octagonal mausoleum rising 54 meters is decorated with beautiful blue and white tile work and dark wood. Dedicated to the Sufi saint Rukn-ud-Din Abul Fath (1251-1335 CE), a revered figure in Pakistani Islam.", history: "Shah Rukn-e-Alam ('Pillar of the World') was a renowned 14th-century Sufi saint of the Suhrawardiyya order. His tomb was originally built by Ghiyas ud-Din Tughluq as his own mausoleum but gifted to the saint's family. It has been a major pilgrimage center for 700 years.", image: "https://picsum.photos/seed/ShahRuknEAlam/800/400" },
  { name: "Shrine of Bahauddin Zakariya", lat: 30.2094, lng: 71.4739, category: "religious", province: "Punjab", rating: 4.7, bestTime: "All year", description: "The most important religious site in Multan, dedicated to the Sufi saint who founded the Suhrawardiyya order in South Asia (1170-1267). The 14th-century octagonal tomb chamber is richly decorated with blue and white tiles. The annual Urs attracts hundreds of thousands of devotees.", history: "Bahauddin Zakariya was one of the most influential Sufi saints of medieval South Asia, instrumental in the spread of Islam in the Punjab. His shrine became a major pilgrimage destination almost immediately after his death in 1267. The current tomb dates from the Sultanate period.", image: "https://picsum.photos/seed/BahaualdinZakariyaShrine/800/400" },
  { name: "Uch Sharif", lat: 29.2250, lng: 71.0450, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "An ancient city in southern Punjab with a remarkable concentration of historic shrines and tombs from the 13th-16th centuries on the banks of the Chenab River. A UNESCO World Heritage Site candidate.", history: "Uch (ancient Alexandria Opiana) was one of the cities founded by Alexander the Great in 325 BC. It became an important city under the Delhi Sultanate as a center of Islamic learning. Devastated by Tamerlane's invasion in 1398 and never fully recovered.", image: "https://picsum.photos/seed/UchSharif/800/400" },
  { name: "Harappa", lat: 30.6290, lng: 72.8640, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "One of the two main cities (along with Mohenjo-daro) of the ancient Indus Valley Civilization, dating back 4,500 years. The archaeological site reveals a sophisticated urban civilization with planned streets, multi-story houses, and an advanced drainage system.", history: "Harappa was a major urban center of the Indus Valley Civilization, existing from approximately 2600-1900 BCE. First excavated by Daya Ram Sahni in 1921-22. The city's advanced town planning demonstrated a remarkably organized society that was entirely unknown to history until this excavation.", image: "https://picsum.photos/seed/Harappa/800/400" },
  { name: "Kalar Kahar Lake", lat: 32.7894, lng: 72.3833, category: "lake", province: "Punjab", rating: 4.4, bestTime: "October to April", description: "A naturally formed salt lake in the Potohar Plateau surrounded by the Khabbeki and Salt Range hills. An important wetland for migratory birds including painted storks and pelicans. Emperor Babur had a garden laid out here during his India campaign.", history: "Mentioned in the memoirs of Emperor Babur (Baburnama) who camped at the lake on his way to conquer India. He had a garden laid out here, now maintained as the Babur Garden. The lake was an important natural water source on the main route from the Khyber to the Punjab.", image: "https://picsum.photos/seed/KalarKaharLake/800/400" },
  { name: "Namal Lake", lat: 32.7000, lng: 71.9000, category: "lake", province: "Punjab", rating: 4.4, bestTime: "November to March", description: "A beautiful manmade reservoir in the Mianwali district of Punjab, surrounded by scrub hills. A designated Ramsar wetland site supporting large populations of migratory and resident waterfowl. The area also contains the historic Namal University established on its shores.", history: "Namal was first developed as an irrigation project during the British period. The lake gained significance as a wildlife habitat, particularly for migratory birds. Namal University was later established with Oxford University collaboration.", image: "https://picsum.photos/seed/NamalLake/800/400" },
  { name: "Faisalabad", lat: 31.4180, lng: 73.0790, category: "city", province: "Punjab", rating: 3.9, bestTime: "October to March", description: "Pakistan's third largest city and textile capital. The historic Clock Tower (Ghanta Ghar) at the center of eight bazaars radiating like the Union Jack flag is the city's most iconic landmark. An industrial powerhouse with a developing cultural scene.", history: "Founded by the British in 1880 as Lyallpur, planned in the shape of a Union Jack flag with the Clock Tower at its center. Large-scale irrigation transformed this dry area into fertile agricultural land. Renamed Faisalabad in 1977 in honor of King Faisal of Saudi Arabia.", image: "https://picsum.photos/seed/Faisalabad/800/400" },
  { name: "Cholistan Desert", lat: 27.9500, lng: 70.5000, category: "desert", province: "Punjab", rating: 4.6, bestTime: "November to February", description: "A vast desert in southern Punjab covering about 26,000 sq km, with towering sand dunes up to 150 meters high. Contains ruins of over 400 ancient Indus Valley Civilization sites. The annual Cholistan Desert Jeep Rally is one of Pakistan's most popular motorsports events.", history: "Cholistan was part of the ancient Hakra River valley that supported the Indus Valley Civilization's eastern settlements before drying up around 1900 BCE. Ruins of over 400 prehistoric sites document this ancient civilization. The current pastoral culture maintains traditions descending from these ancient populations.", image: "https://picsum.photos/seed/CholitanDesert/800/400" },
  { name: "Lal Suhanra National Park", lat: 29.4000, lng: 72.0000, category: "wildlife", province: "Punjab", rating: 4.4, bestTime: "October to February", description: "A sanctuary for blackbuck antelope near Bahawalpur, successfully reintroduced here. The park encompasses both Cholistan desert scrubland and irrigated agricultural land, supporting diverse wildlife. Also a major winter birding destination.", history: "Established in 1972 and expanded to cover 153,000 hectares, created primarily to protect the blackbuck antelope hunted to near extinction in the Punjab. The reintroduction program has been successful with the population recovering significantly.", image: "https://picsum.photos/seed/LalSuhanraPark/800/400" },
  { name: "Changa Manga Forest", lat: 31.0000, lng: 73.9667, category: "wildlife", province: "Punjab", rating: 4.2, bestTime: "October to March", description: "One of the largest man-made forests in the world covering approximately 12,000 acres near Lahore. Provides a green escape for Lahore residents and is home to numerous bird species. A narrow-gauge railway through the forest is a popular attraction.", history: "Planted by the British colonial administration in 1866 to provide sustainable timber and firewood for Punjab railway steam locomotives. Named after two local dacoit brothers who were hanged and their land used for planting.", image: "https://picsum.photos/seed/ChangaManga/800/400" },
  { name: "Pakpattan Shrine (Baba Farid)", lat: 30.3441, lng: 73.3872, category: "religious", province: "Punjab", rating: 4.6, bestTime: "All year (March Urs is best)", description: "The shrine of Sufi saint Baba Farid (Fariduddin Ganjshakar) is one of the most venerated Sufi shrines in Pakistan. Baba Farid (1179-1265) was a revered mystic of the Chishti order whose poetry in Punjabi is included in the Sikh scripture Guru Granth Sahib. The annual Urs attracts millions of devotees.", history: "Baba Farid was the third great Chishti Sufi saint in South Asia. Remarkably his verse is included in the Guru Granth Sahib, making him revered by both Muslims and Sikhs. His shrine has been the destination of pilgrimage across religious lines for 750 years.", image: "https://picsum.photos/seed/PakpattanShrine/800/400" },
  { name: "Sialkot", lat: 32.4924, lng: 74.5319, category: "city", province: "Punjab", rating: 4.1, bestTime: "October to March", description: "Known as the 'City of Sports' for its globally famed manufacturing of sports goods including footballs, cricket equipment, and hockey sticks. Also famous for world-class surgical instruments. The historic Sialkot Fort and shrines of Sufi saints give cultural depth.", history: "One of Pakistan's oldest cities with history spanning over 2,000 years. The sports goods industry grew in the 20th century when the city's craftsmen developed the industry that now supplies products to major international brands. Birthplace of Pakistan's national poet Allama Muhammad Iqbal.", image: "https://picsum.photos/seed/Sialkot/800/400" },
  { name: "Lahore Food Street (Fort Road)", lat: 31.5591, lng: 74.3136, category: "city", province: "Punjab", rating: 4.5, bestTime: "All year (evenings)", description: "Lahore's Food Street in the historic Fort Road area offers an extraordinary outdoor dining experience in a beautifully lit heritage setting. Serves authentic Lahori cuisine including Lahori karahi, paya (trotters), and halwa puri.", history: "Developed by the City District Government of Lahore in 2010, transforming a run-down area near the fort into a prime tourist and dining destination. One of the most successful urban heritage tourism projects in Pakistan.", image: "https://picsum.photos/seed/LahoriFood/800/400" },
  { name: "Shalimar Food Street (Hussain Chowk)", lat: 31.5812, lng: 74.3201, category: "city", province: "Punjab", rating: 4.4, bestTime: "October to March (evenings)", description: "Another famous food destination in Lahore's Walled City area, famous for authentic Lahori breakfast—halwa puri, chana, and nihari. The narrow lanes at dawn full of street food vendors is one of the most atmospheric experiences in Pakistan.", history: "The food culture of Lahore's Walled City has developed over centuries, with breakfast food culture particularly influenced by the Mughal era traditions of royal cooks and kitchens whose legacy lives on in the surviving family restaurants.", image: "https://picsum.photos/seed/LahoriBreakfast/800/400" },

  // ═══════════════════════════════════════════
  // SINDH
  // ═══════════════════════════════════════════

  { name: "Mohenjo-daro", lat: 27.3294, lng: 68.1385, category: "historical", province: "Sindh", rating: 4.8, bestTime: "November to February", description: "One of the earliest and largest settlements of the ancient Indus Valley Civilization, dating back approximately 4,500 years. Remarkably planned with grid layout, advanced drainage, and large structures more sophisticated than contemporary civilizations in Egypt and Mesopotamia. A UNESCO World Heritage Site.", history: "Built around 2500 BCE and flourishing for about 700 years before its decline around 1900 BCE. The city had a population of up to 40,000 at its peak. Discovered in 1922 by archaeologist Rakhaldas Bandyopadhyay. The nearby museum houses the famous Dancing Girl and Priest-King sculptures.", image: "https://picsum.photos/seed/MohenjoDaro/800/400" },
  { name: "Makli Necropolis", lat: 24.7466, lng: 67.9090, category: "historical", province: "Sindh", rating: 4.7, bestTime: "November to February", description: "Near Thatta, one of the largest funerary sites in the world containing 125,000 graves and tombs over 10 sq km. Tombs of Sindh's ruling dynasties represent a magnificent progression of architectural styles spanning the 14th to 18th centuries. A UNESCO World Heritage Site.", history: "Makli has been used as a burial ground for over 500 years containing tombs of rulers of the Samma, Arghun, Tarkhan, and Talpur dynasties. Local tradition holds 125,000 saints are buried here equal to those at Mecca. Represents one of the most important concentrations of Islamic funerary architecture in South Asia.", image: "https://picsum.photos/seed/MakliNecropolis/800/400" },
  { name: "Ranikot Fort (Great Wall of Sindh)", lat: 26.1500, lng: 67.8333, category: "historical", province: "Sindh", rating: 4.8, bestTime: "November to February", description: "Claimed to be the world's largest fort with its perimeter wall stretching over 26 km, known as the 'Great Wall of Sindh.' One of the most mysterious historical sites in Pakistan set in rugged hills. The precise history and purpose remain subjects of debate among historians.", history: "Origins are uncertain, with theories ranging from Sassanid to medieval Islamic construction. Certainly in use by the Talpur Mirs in the late 18th century. Its immense size and remote location have puzzled historians who suggest it may have protected wealthy trading routes of Sindh.", image: "https://picsum.photos/seed/RanikotFort/800/400" },
  { name: "Keenjhar Lake", lat: 24.9570, lng: 68.0060, category: "lake", province: "Sindh", rating: 4.5, bestTime: "November to March", description: "The second largest freshwater lake in Pakistan and a major water source for Karachi. A designated Ramsar wetland site important for migratory birds and resident waterfowl. The tomb of Noori (a legendary Sindhi figure) on an island in the lake is a notable attraction.", history: "The lake is the site of one of Sindh's most famous folk legends — the love story of Prince Jam Tamachi and Noori, a fisherwoman whose tomb sits on an island. The legend was immortalized in Sindhi folk poetry and has made the lake a place of romantic pilgrimage.", image: "https://picsum.photos/seed/KeenjharLake/800/400" },
  { name: "Shah Jahan Mosque Thatta", lat: 24.7447, lng: 67.9193, category: "historical", province: "Sindh", rating: 4.7, bestTime: "November to February", description: "Considered one of the finest examples of Mughal religious architecture with extraordinary blue-tiled decorative work. The mosque has 93 domes and a complex acoustic system allowing sounds from the entrance to be heard clearly at the far end without amplification. A UNESCO World Heritage Site.", history: "Built between 1644-47 AD by Emperor Shah Jahan as a gratitude gift to the people of Thatta after they sheltered him when he was in rebellion against his father. The mosque's extraordinary acoustic design has been studied by modern engineers.", image: "https://picsum.photos/seed/ShahJahanMosquThatta/800/400" },
  { name: "Lal Shahbaz Qalandar Shrine (Sehwan)", lat: 26.4339, lng: 67.8652, category: "religious", province: "Sindh", rating: 4.7, bestTime: "All year (March festival)", description: "One of the most important Sufi shrines in Pakistan, dedicated to the Sufi saint Syed Muhammad Usman Marwandi (1177-1274 CE). The Thursday evening dhamal (ecstatic Sufi dance) draws thousands of devotees into a state of spiritual trance. The annual Urs festival attracts millions of pilgrims.", history: "Lal Shahbaz Qalandar was a 13th century Sufi saint of the Qalandariyya order. His shrine became a center of Sufi activity immediately after his death drawing devotees across religious boundaries. The shrine was damaged in a devastating 2017 suicide bombing but has since been fully restored.", image: "https://picsum.photos/seed/LalShahbaz/800/400" },
  { name: "Karachi", lat: 24.8607, lng: 67.0011, category: "city", province: "Sindh", rating: 4.2, bestTime: "November to February", description: "Pakistan's largest city, economic capital, and main seaport, home to over 20 million people. Offers a vibrant mix of cultures, cuisines, beaches, and urban experiences. From Clifton beach to the bustling Saddar district and the Empress Market, Karachi captures the energy of a modern South Asian megacity.", history: "A small fishing village until the British developed it into a major port city in the early 19th century following their conquest of Sindh in 1843. Was the capital of Pakistan until 1960 when Islamabad was made the capital. Massive post-partition migration transformed the city's demographics.", image: "https://picsum.photos/seed/Karachi/800/400" },
  { name: "Clifton Beach (Sea View)", lat: 24.8138, lng: 67.0220, category: "beach", province: "Sindh", rating: 4.0, bestTime: "November to February", description: "Karachi's most famous beach, stretching along the Arabian Sea in the upscale Clifton neighborhood. A major recreational area with camel and horse rides, food stalls, and amusement rides. The promenade is especially lively in the evenings and on weekends.", history: "Clifton was developed as an upscale residential area by the British, with the seafront becoming a recreational hub. Muhammad Ali Jinnah's residence (now a museum) is located in Clifton. After independence the beach became accessible to all Karachiites.", image: "https://picsum.photos/seed/CliftonBeach/800/400" },
  { name: "Manora Island", lat: 24.7994, lng: 66.9747, category: "historical", province: "Sindh", rating: 4.3, bestTime: "November to February", description: "A small island at the entrance to Karachi harbor accessible by short boat ride from Kemari. Features a distinctive historic lighthouse, colonial era structures, Hindu temples, and old churches creating an eclectic historical landscape against the backdrop of the Arabian Sea.", history: "Manora has been settled since ancient times and was an important maritime landmark. A Portuguese fort was built here in the 16th century. The British built the iconic lighthouse. The island was significantly active during World War II as a naval base.", image: "https://picsum.photos/seed/ManoraIsland/800/400" },
  { name: "Empress Market", lat: 24.8617, lng: 67.0108, category: "historical", province: "Sindh", rating: 4.4, bestTime: "November to March", description: "A magnificent Victorian-era covered market built in 1889 to commemorate Queen Victoria's Golden Jubilee. The Gothic style red brick building with its prominent clock tower is one of Karachi's most iconic landmarks. Inside, the bustling market sells everything from spices and meat to pottery and crafts.", history: "Built in 1889 during the reign of Queen Victoria (Empress of India). Has served as Karachi's main covered marketplace for over 130 years and is the subject of ongoing debates about modernization versus heritage preservation.", image: "https://picsum.photos/seed/EmpressMarket/800/400" },
  { name: "Abdullah Shah Ghazi Shrine", lat: 24.8289, lng: 67.0278, category: "religious", province: "Sindh", rating: 4.5, bestTime: "All year", description: "The shrine of the patron saint of Karachi on a hilltop in Clifton. The sea-facing location makes the shrine particularly atmospheric at sunset. Thousands of devotees visit daily and Thursday evening devotions are especially vibrant.", history: "Abdullah Shah Ghazi was an 8th-century Arab missionary who came to Sindh and is venerated as the patron saint of Karachi. His shrine on Clifton hillock has been a place of veneration and pilgrimage for over a thousand years.", image: "https://picsum.photos/seed/AbdullahShahGhazi/800/400" },
  { name: "Banbhore (Ancient Debal)", lat: 24.7000, lng: 67.5500, category: "historical", province: "Sindh", rating: 4.5, bestTime: "November to February", description: "An important archaeological site on the Gharo Creek east of Karachi, identified by many historians as the ancient port city of Debal — the landing point of Arab general Muhammad bin Qasim's invasion fleet in 711 CE. Reveals layers of settlement from the Scytho-Parthian period through early Islamic occupation.", history: "Banbhore is significant as the probable site where the Arab presence in South Asia began. When Muhammad bin Qasim's army landed in 711 CE it marked the beginning of Islamic rule in the subcontinent. The site shows occupation from approximately the 1st century CE through the 13th century.", image: "https://picsum.photos/seed/Banbhore/800/400" },
  { name: "Manchar Lake", lat: 26.4333, lng: 67.6000, category: "lake", province: "Sindh", rating: 4.5, bestTime: "November to February", description: "Asia's largest natural freshwater lake during monsoon season, extending over 250 sq km in Dadu district. Home to the Mohana fishing community who live their entire lives on floating bamboo platforms on the lake. The lake's migratory bird populations are extraordinary including thousands of flamingos.", history: "Manchar has been a source of livelihood for the Mohana (boat people) communities for thousands of years. The lake and its Mohana community are documented as a unique surviving example of freshwater nomadism. The lake has faced serious environmental challenges due to agricultural drainage and industrial waste.", image: "https://picsum.photos/seed/MancharLake/800/400" },
  { name: "Kot Diji Fort", lat: 27.3442, lng: 68.7137, category: "historical", province: "Sindh", rating: 4.5, bestTime: "November to February", description: "An 18th-century mud-brick fort near Khairpur in Sindh that overlooks the surrounding plains from a natural hill. The capital of the Talpur rulers of Khairpur state, presenting an impressive example of Sindhi-Baloch fortification architecture.", history: "Built in the late 18th century by Mir Sohrab Khan Talpur, founder of the Khanate of Khairpur. The Talpur Mirs ruled Sindh from 1783 until the British conquest in 1843 and Kot Diji was one of their main strongholds.", image: "https://picsum.photos/seed/KotDijiFort/800/400" },
  { name: "Hyderabad", lat: 25.3792, lng: 68.3683, category: "city", province: "Sindh", rating: 4.1, bestTime: "November to February", description: "Sindh's second largest city with a rich cultural heritage, known for its Sindhi silk and embroidery work, lacquered furniture, and glass bangles. Important Sufi shrines and remains of the Talpur Mirs' fort. The narrow lanes of the old city with handicraft workshops are fascinating.", history: "Founded in 1768 by Mian Ghulam Shah Kalhoro on the bank of the Indus River. Became the capital of Sindh under the Talpur Mirs until the British conquest in 1843. The famous Battle of Miani (1843) near Hyderabad brought Sindh under British rule.", image: "https://picsum.photos/seed/Hyderabad/800/400" },
  { name: "Kirthar National Park", lat: 26.3000, lng: 67.5000, category: "wildlife", province: "Sindh", rating: 4.5, bestTime: "November to February", description: "One of Pakistan's oldest and largest national parks, covering 3,087 sq km of rugged Kirthar range mountains. The primary habitat for the endangered Sindh Wild Goat (Sindh ibex), also supporting urial sheep, Balochistan bear, chinkara gazelle, and leopard.", history: "Established in 1974 as one of Pakistan's founding national parks. The park lies in the ancient Kirthar mountain range that formed the natural eastern boundary of the Balochistan plateau. Archaeological remains include ruins of Kahu-jo-Daro, an Indus Valley Civilization settlement.", image: "https://picsum.photos/seed/KirtharPark/800/400" },
  { name: "Haleji Lake", lat: 24.8017, lng: 67.7700, category: "lake", province: "Sindh", rating: 4.4, bestTime: "November to March", description: "A freshwater reservoir and bird sanctuary east of Karachi serving as one of the most important winter bird habitats in Pakistan. A Ramsar Wetland site hosting hundreds of thousands of migratory waterbirds from Siberia, Central Asia, and Europe. Famous for painted storks, flamingos, and pelicans.", history: "Created in 1968 as a reservoir to supply drinking water to Karachi. The water body quickly became an important bird habitat. Upgraded to a wildlife sanctuary in 1972 and included in the Ramsar List. Attracts some of the largest concentrations of wintering birds in South Asia.", image: "https://picsum.photos/seed/HalejiLake/800/400" },
  { name: "Sukkur Barrage", lat: 27.7035, lng: 68.8675, category: "historical", province: "Sindh", rating: 4.4, bestTime: "November to February", description: "A massive irrigation structure that when built in 1932 was the world's largest irrigation project. The barrage feeds seven massive irrigation canals providing water to 5.4 million acres of agricultural land in Sindh. It also connects upper and lower Sindh.", history: "Constructed between 1923-1932 by the British colonial administration at a cost of £6 million. The project transformed the agricultural economy of Sindh, bringing millions of acres of desert under cultivation. Stands as a testament to the engineering ambition of the colonial era.", image: "https://picsum.photos/seed/SukkurBarrage/800/400" },
  { name: "Larkana", lat: 27.5557, lng: 68.2143, category: "city", province: "Sindh", rating: 4.0, bestTime: "November to February", description: "The main city of northern Sindh and political stronghold of the Bhutto family. Serves as the gateway to Mohenjo-daro archaeological site. Known for its Sindhi cuisine and cultural events.", history: "Ancestral home of the Bhutto family. Zulfikar Ali Bhutto, Pakistan's Prime Minister from 1973-77, came from Larkana, as did his daughter Benazir Bhutto who became Prime Minister twice. The city's political significance has shaped its development.", image: "https://picsum.photos/seed/Larkana/800/400" },
  { name: "French Beach", lat: 24.8750, lng: 66.7167, category: "beach", province: "Sindh", rating: 4.4, bestTime: "November to February", description: "One of the cleanest and most beautiful beaches near Karachi, located about 35 km west of the city. Rocky coves and sandy beaches with relatively clear water offer a refreshing escape from the city. Popular with camping groups.", history: "French Beach got its informal name in the 1950s when French engineers working on Karachi-area projects used to recreate here. The beach area has been used by Karachi residents as an escape from the city since the British colonial period.", image: "https://picsum.photos/seed/FrenchBeach/800/400" },
  { name: "Hawkes Bay Beach", lat: 24.8375, lng: 66.8711, category: "beach", province: "Sindh", rating: 4.1, bestTime: "November to February", description: "A popular beach west of Karachi with relatively calmer waters compared to Clifton Beach. A nesting site for endangered green sea turtles. The beach is popular for swimming and picnics with Karachi residents escaping the city.", history: "Hawkes Bay has been a popular Karachi beach destination since the colonial period when it was known for its calmer waters. The turtle nesting here has been the focus of conservation efforts by Pakistan's WWF and other organizations for decades.", image: "https://picsum.photos/seed/HawkesBay/800/400" },

  // ═══════════════════════════════════════════
  // BALOCHISTAN
  // ═══════════════════════════════════════════

  { name: "Gwadar", lat: 25.1264, lng: 62.3225, category: "city", province: "Balochistan", rating: 4.4, bestTime: "October to March", description: "A fast-developing deep-sea port city on the Balochistan coast, central to the China-Pakistan Economic Corridor (CPEC). The city has dramatic coastal landscape with the Koh-e-Batil promontory rising from the Arabian Sea creating a natural harbor. Beaches, seafood, and expanding infrastructure make it increasingly interesting.", history: "Historically a small fishing village that was actually part of Oman (Muscat) until 1958 when Pakistan purchased it for 3 million US dollars. The China-Pakistan Economic Corridor (CPEC), announced in 2015, made Gwadar the centerpiece of a massive infrastructure investment as the endpoint of a trade route from western China.", image: "https://picsum.photos/seed/Gwadar/800/400" },
  { name: "Hingol National Park", lat: 25.5170, lng: 65.5076, category: "wildlife", province: "Balochistan", rating: 4.7, bestTime: "November to February", description: "Pakistan's largest national park covering 6,100 sq km along the Makran coast and inland mountains. Contains dramatic Makran beaches, mud volcanoes, and the magnificent Kund Malir beach. The sandstone rock formations including Princess of Hope create a surreal landscape.", history: "Established in 1988 to protect the diverse ecosystems of the Makran coast. The Hinglaj temple within the park is one of the most important Hindu pilgrimage sites in Pakistan, attracting thousands of Hindu pilgrims annually.", image: "https://picsum.photos/seed/HingolPark/800/400" },
  { name: "Princess of Hope", lat: 25.4160, lng: 65.5090, category: "mountain", province: "Balochistan", rating: 4.6, bestTime: "November to February", description: "A remarkable natural rock formation in the Makran coastal mountains, shaped by erosion into a silhouette resembling a standing woman. Named by actress Angelina Jolie during her 2002 visit to Pakistan. One of the most photographed natural features along the Makran Coastal Highway.", history: "A natural formation created by thousands of years of wind and water erosion on soft coastal sandstone mountains. Gained international fame when Angelina Jolie visited the area and gave it this evocative name during her advocacy work for Afghan refugees.", image: "https://picsum.photos/seed/PrincessOfHope/800/400" },
  { name: "Kund Malir Beach", lat: 25.3850, lng: 66.7225, category: "beach", province: "Balochistan", rating: 4.8, bestTime: "November to February", description: "Considered one of the most beautiful beaches in Pakistan, with pristine white sand framed by dramatic sandstone cliffs in Hingol National Park. The combination of dramatic inland geology with turquoise Arabian Sea creates an extraordinary landscape. Camping here under starry skies is one of the best outdoor experiences in Pakistan.", history: "Known to the local Baloch fishing communities for centuries but gained wider attention with the completion of the Makran Coastal Highway in 2004. The beach remains largely undeveloped, which paradoxically makes it one of the most beautiful natural beaches in Pakistan.", image: "https://picsum.photos/seed/KundMalirBeach/800/400" },
  { name: "Makran Coastal Highway", lat: 25.2000, lng: 64.0000, category: "beach", province: "Balochistan", rating: 4.7, bestTime: "November to February", description: "One of the most spectacular and scenic driving routes in Pakistan, running along the Arabian Sea coast from Karachi to Gwadar (653 km). Passes through dramatic coastal cliffs, pristine beaches, fishing villages, and the vast Hingol National Park. The coastline is largely untouched.", history: "Completed in 2004, significantly improving connectivity between Karachi and the Balochistan coast. The highway opened up the Makran coast to commercial development and tourism. Its completion was a major infrastructure achievement given the challenging coastal terrain.", image: "https://picsum.photos/seed/MakranHighway/800/400" },
  { name: "Ziarat", lat: 30.3826, lng: 67.7256, category: "mountain", province: "Balochistan", rating: 4.5, bestTime: "May to October", description: "A hill station famous for its ancient juniper forests with some specimens estimated to be over 5,000 years old — among the oldest living organisms on earth. Known for its cool climate and the historic Residency where Pakistan's founding father Muhammad Ali Jinnah spent his final days.", history: "Gained historical significance as the location where Muhammad Ali Jinnah came to recuperate in summer 1948. The Ziarat Residency is preserved as a protected national monument. The Ziarat Juniper Forest is one of the largest juniper forests in the world.", image: "https://picsum.photos/seed/Ziarat/800/400" },
  { name: "Quaid Residency Ziarat", lat: 30.3806, lng: 67.7272, category: "historical", province: "Balochistan", rating: 4.6, bestTime: "May to September", description: "A Victorian-era wooden building where Muhammad Ali Jinnah, the founder of Pakistan, spent the last two months of his life in 1948. Now a national museum maintained as a monument to Jinnah. Seriously damaged in a terrorist attack in 2013 but has since been restored.", history: "Built in 1892 during the British colonial era as a summer residence for the Agent to the Governor General for Balochistan. Jinnah arrived gravely ill with tuberculosis on July 14, 1948, and spent his final weeks here before returning to Karachi where he died on September 11, 1948.", image: "https://picsum.photos/seed/QuaidResidencyZiarat/800/400" },
  { name: "Hinglaj Temple", lat: 25.5082, lng: 65.5091, category: "religious", province: "Balochistan", rating: 4.7, bestTime: "March-April (Hinglaj Yatra festival)", description: "The most important Hindu pilgrimage site in Pakistan, located within Hingol National Park. Each year in late March-April the 'Hinglaj Yatra' draws over 100,000 Hindu and Zikri pilgrims. The temple is dedicated to the goddess Hinglaj Mata, considered an incarnation of Sati/Parvati.", history: "Hinglaj is one of the 51 Shakti Peethas associated with the goddess Sati. According to Hindu mythology, Sati's head fell at Hinglaj. The temple has been a pilgrimage site for at least 1,000 years. Protected and maintained with government support as evidence of Pakistan's multi-faith heritage.", image: "https://picsum.photos/seed/HinglajTemple/800/400" },
  { name: "Quetta", lat: 30.1798, lng: 66.9750, category: "city", province: "Balochistan", rating: 4.2, bestTime: "May to September", description: "The capital of Balochistan, known as the 'Fruit Garden of Pakistan' for its extraordinary fruit orchards producing apples, cherries, grapes, and pomegranates. The city has a distinctive cosmopolitan Afghan-Baloch-Pashto culture and is famous for its dried fruits and handicrafts.", history: "Historically a small fort and settlement that became strategically important between Afghanistan and India. Significantly expanded as a British military cantonment and became the headquarters of the Balochistan Force. Almost completely destroyed by a devastating earthquake in 1935 that killed 60,000 people.", image: "https://picsum.photos/seed/Quetta/800/400" },
  { name: "Hanna Lake", lat: 30.2580, lng: 67.1000, category: "lake", province: "Balochistan", rating: 4.4, bestTime: "March to October", description: "A scenic reservoir in the Urak Valley, 10 km northeast of Quetta. The turquoise lake surrounded by rocky hills and pine trees is Quetta's most popular recreational area. Boat rides, picnics, and fishing are popular activities.", history: "Hanna Lake was created as a reservoir by the British colonial administration in the early 20th century to supply water to Quetta. Named after Colonel Hanna who supervised its construction. The surrounding area was developed as a recreational park by the British.", image: "https://picsum.photos/seed/HannaLake/800/400" },
  { name: "Bolan Pass", lat: 29.7500, lng: 67.5000, category: "mountain", province: "Balochistan", rating: 4.5, bestTime: "October to March", description: "A significant mountain pass connecting Pakistan's Balochistan plateau with the Sindh plains, historically one of the main routes into South Asia from Central Asia. Follows a dramatic gorge carved by the Bolan River through the mountains. The railway viaduct crossing the pass is a remarkable feat of 19th-century engineering.", history: "Used as a major invasion and trade route into South Asia for at least 3,000 years. During the first Afghan War (1839-42) the British used Bolan Pass as a main supply route. The Bolan Railway completed in 1887 with its spiral reversals and tunnels was one of the most challenging railway engineering projects of the colonial era.", image: "https://picsum.photos/seed/BolanPass/800/400" },
  { name: "Mehrgarh", lat: 29.3833, lng: 67.6167, category: "historical", province: "Balochistan", rating: 4.8, bestTime: "November to February", description: "One of the most important Neolithic sites in the world, documenting the transition from hunter-gatherer to settled farming life in South Asia beginning around 7000 BCE. Predates the Indus Valley Civilization by 4,500 years. Excavations have revealed evidence of the world's earliest known dentistry.", history: "Discovered in 1974 by a French archaeological team. The site reveals a continuous sequence of occupation from the Neolithic period (7000 BCE) through the Bronze Age Indus Valley Civilization (2500 BCE). The world's earliest evidence of dental filling has been found at Mehrgarh.", image: "https://picsum.photos/seed/Mehrgarh/800/400" },
  { name: "Ormara Beach", lat: 25.2100, lng: 64.6367, category: "beach", province: "Balochistan", rating: 4.5, bestTime: "November to February", description: "A small fishermen's town on the Makran coast with beautiful beaches and a unique rocky peninsula jutting into the Arabian Sea. The town is a major fishing center and the freshly caught seafood is exceptional. The clear waters are excellent for snorkeling and the coastal scenery is spectacular.", history: "Ormara has been a fishing settlement for centuries, its natural harbor making it an important maritime community. The town's Portuguese connections date to the 16th century when the Portuguese established a presence along the Makran coast. The Pakistan Navy maintains a base nearby.", image: "https://picsum.photos/seed/OrmaraBeach/800/400" },
  { name: "Astola Island", lat: 25.0977, lng: 63.8612, category: "beach", province: "Balochistan", rating: 4.7, bestTime: "November to February", description: "The largest offshore island in Pakistan in the Arabian Sea, about 40 km from the Makran coast. The pristine uninhabited island with rugged cliffs, sandy beaches, and crystal-clear waters is a paradise for divers and nature lovers. Green sea turtles nest on its beaches.", history: "Known to ancient mariners as a navigation landmark on the Makran coast sea route. Contains a small Hindu temple dedicated to the goddess Kali, indicating historical significance to Hindu Baloch fishing communities. Designated as Pakistan's first Marine Protected Area in 2017.", image: "https://picsum.photos/seed/AstolaIsland/800/400" },
  { name: "Gadani Beach & Ship Breaking", lat: 25.1167, lng: 66.7333, category: "beach", province: "Balochistan", rating: 4.2, bestTime: "November to March", description: "Gadani is famous for its ship-breaking yard — one of the world's largest — where massive ocean vessels are dismantled by hand on the beach. The spectacle of giant ships beached and being broken apart is surreal and dramatic.", history: "Gadani's ship-breaking industry began in the 1970s and by the 1980s had become one of the three largest in the world. At its peak it was breaking 80+ ships per year. Economic competition from South Asia and regulatory challenges have reduced the industry's scale in recent decades.", image: "https://picsum.photos/seed/GadaniBeach/800/400" },
  { name: "Kalat", lat: 29.0231, lng: 66.5903, category: "historical", province: "Balochistan", rating: 4.2, bestTime: "April to October", description: "The historical capital of the Khanate of Kalat, the most powerful Baloch political state before British conquest. Situated in the Kalat plateau at 2,072m offering a cool climate. The remains of the Khan's fort and historical buildings are visible in the old city.", history: "The Khanate of Kalat was founded in 1666 and at its height controlled most of Balochistan. The Khan of Kalat famously declared independence on August 11, 1947, one day before Pakistan, but acceded to Pakistan on March 27, 1948. The khanate's history is deep connected to Baloch national identity.", image: "https://picsum.photos/seed/Kalat/800/400" },
  { name: "Turbat", lat: 26.0012, lng: 63.0444, category: "city", province: "Balochistan", rating: 3.9, bestTime: "October to March", description: "The second largest city in Balochistan and the main urban center of the Makran region. Known for its date palm cultivation — dates are Turbat's main agricultural product. The surrounding Makran landscape of barren mountains and desert plains represents a distinctive environment.", history: "Turbat (Kech) was historically the center of the Kech principality in Makran. The Kech Valley with its date palm groves and seasonal river has been inhabited for thousands of years. The area was ruled by local Baloch tribal chiefs before coming under the Khan of Kalat.", image: "https://picsum.photos/seed/Turbat/800/400" },
  { name: "Gwadar Head (Koh-e-Batil)", lat: 25.1830, lng: 62.2910, category: "mountain", province: "Balochistan", rating: 4.5, bestTime: "October to March", description: "The remarkable Gwadar Head is a rocky promontory rising dramatically from the Arabian Sea, connected to the mainland by a narrow sand spit. The panoramic views from the top over the deep blue sea and the developing port of Gwadar are extraordinary. One of the most dramatic coastal landscapes in Pakistan.", history: "Gwadar Head has been a vital navigation landmark for Arabian Sea sailors for thousands of years. The promontory's natural harbor on its eastern side was the key geographic feature that made Gwadar an ideal location for a deep-sea port. The area is mentioned in accounts of Portuguese explorers in the 16th century.", image: "https://picsum.photos/seed/GwadarHead/800/400" },
  { name: "Bolan River Gorge", lat: 29.5500, lng: 67.3000, category: "mountain", province: "Balochistan", rating: 4.4, bestTime: "October to March", description: "The Bolan River courses through a spectacular narrow gorge in the Brahui mountains forming one of the most dramatic landscape features in Balochistan. The layered rock formations display millions of years of geological history and the gorge carries the historic Bolan Pass route and railway line.", history: "Archaeological evidence from Mehrgarh near the Bolan River's emergence from the mountains shows it was one of the earliest farming communities in South Asia, dating to 7000 BCE. The Bolan Route was used by Indo-Iranian peoples migrating into South Asia and later by trade and military expeditions.", image: "https://picsum.photos/seed/BolanGorge/800/400" },
  { name: "Sibi Mela", lat: 29.5596, lng: 67.8828, category: "historical", province: "Balochistan", rating: 4.1, bestTime: "February", description: "Sibi is a city in Balochistan famous for hosting Pakistan's most popular livestock festival, the Sibi Mela. The historic town was the winter headquarters of Alexander the Great during his Balochistan campaign. The Sibi Mela festival held in February is the largest livestock fair in Pakistan.", history: "Sibi (ancient Sivbi) is one of the oldest settlements in Balochistan. During Alexander the Great's campaign it was an important city and winter camp for his army. In medieval times it served as the administrative center for eastern Balochistan.", image: "https://picsum.photos/seed/Sibi/800/400" },

  // ═══════════════════════════════════════════
  // AZAD KASHMIR (AJK)
  // ═══════════════════════════════════════════

  { name: "Neelum Valley", lat: 34.5892, lng: 73.9070, category: "valley", province: "AJK", rating: 4.9, bestTime: "April to October", description: "Azad Kashmir's most spectacular region, following the Neelum River for over 200km through dense forests, waterfalls, and mountain scenery. The valley is divided from Indian-administered Kashmir by the Line of Control. The scenic beauty becomes more dramatic as you travel deeper into the valley.", history: "Historically part of the princely state of Kashmir, divided between Pakistan and India-administered territories following the 1948 war. The 2005 earthquake caused devastating destruction in parts of the valley. The region continues to have strategic significance due to its proximity to the Line of Control.", image: "https://picsum.photos/seed/NeelumValley/800/400" },
  { name: "Arang Kel", lat: 34.8370, lng: 74.2070, category: "mountain", province: "AJK", rating: 4.8, bestTime: "April to October", description: "A beautiful village near Kel in Neelum Valley, accessible by a stunning gondola ride across the Neelum River followed by a 2-hour hike. The village is perched on a picturesque shelf with terraced fields and traditional wooden houses against a backdrop of dramatic peaks.", history: "A traditional Kashmiri mountain village that has existed for centuries. The village received significant attention after photos of its extraordinary setting spread on social media, making it one of the most sought-after destinations in Azad Kashmir.", image: "https://picsum.photos/seed/ArangKel/800/400" },
  { name: "Ratti Gali Lake", lat: 34.8173, lng: 74.2105, category: "lake", province: "AJK", rating: 4.9, bestTime: "July to September", description: "A stunning alpine lake above the Kel area in Neelum Valley at around 3,700m. The turquoise lake nestled between dramatic snow-capped peaks is one of the most beautiful lakes in Azad Kashmir. Accessible by a trek from Kel through beautiful alpine meadows.", history: "Known to local herdsmen who used the surrounding meadows as summer pasture, but gained wider fame only in the early 21st century through social media. The lake's pristine beauty has made it one of the most popular trekking destinations in Pakistan.", image: "https://picsum.photos/seed/RattiGaliLake/800/400" },
  { name: "Muzaffarabad", lat: 34.3700, lng: 73.4713, category: "city", province: "AJK", rating: 4.2, bestTime: "March to November", description: "The capital of Azad Kashmir, situated at the confluence of the Neelum and Jhelum rivers surrounded by scenic mountains. The city serves as gateway to the beautiful Neelum Valley. The Red Fort overlooking the Jhelum River is the city's main historical attraction.", history: "Became the capital of Azad Kashmir following the first Indo-Pakistani war in 1948. The city was severely damaged in the 2005 earthquake (7.6 Richter scale) that killed over 87,000 people in AJK and KPK. Rebuilding transformed the city substantially.", image: "https://picsum.photos/seed/Muzaffarabad/800/400" },
  { name: "Leepa Valley", lat: 34.3833, lng: 73.7333, category: "valley", province: "AJK", rating: 4.8, bestTime: "June to October", description: "Often called the 'Switzerland of Azad Kashmir', a picturesque valley with traditional wooden villages, terraced fields, and apple orchards. Particularly stunning in autumn when apple trees turn red and orange. The valley borders Indian administered Kashmir and offers breathtaking views.", history: "Leepa Valley has been inhabited for centuries. It became a major domestic tourism destination in the early 21st century. The famous road built to access the valley is known as the 'Jehlum Valley Road.'", image: "https://picsum.photos/seed/LeepaValley/800/400" },
  { name: "Taobat (Neelum)", lat: 34.9667, lng: 74.6000, category: "mountain", province: "AJK", rating: 4.7, bestTime: "June to September", description: "The last major village accessible by road in the Neelum Valley. Spectacular mountain scenery near Taobat with glaciated peaks and pristine forests makes it one of the most beautiful spots in AJK. Several trekking routes into high-altitude areas begin from here.", history: "Taobat sits very close to the Line of Control and historically was a frontier crossing point. The area was significantly affected by the 1965 and 1971 Indo-Pakistan wars. Development of tourism in Neelum Valley reached Taobat relatively late due to security concerns.", image: "https://picsum.photos/seed/Taobat/800/400" },
  { name: "Sharda Ruins (AJK)", lat: 34.7900, lng: 74.2050, category: "historical", province: "AJK", rating: 4.5, bestTime: "April to October", description: "The ruins of the famous Sharada Peeth temple dedicated to the goddess Saraswati in Neelum Valley. The site was a major center of Hindu and Buddhist learning for centuries. The ruins and scenic Neelum River setting make it a fascinating destination.", history: "Sharada Peeth was one of the 51 Shakti Peethas and the most important Hindu educational center in the Kashmir region. The Sharda script (ancestor of Devanagari) was developed here. The temple complex was abandoned in the 15th century and has been in ruins since.", image: "https://picsum.photos/seed/ShardaTemple/800/400" },
  { name: "Rawalakot", lat: 33.8576, lng: 73.7614, category: "city", province: "AJK", rating: 4.2, bestTime: "March to November", description: "A pleasant forest-ringed town in Azad Kashmir, situated in a broad valley at 1,676m. The surrounding hills with their dense oak and pine forests and the pleasant climate make it a nice base for exploring Poonch district. Nearby Sudhan Gali and Banjosa Lake are popular weekend destinations.", history: "The main town of the Poonch district of Azad Kashmir. The Poonch region has a distinct identity within the broader Kashmir narrative. The area was one of the main theaters of the 1947 war that partitioned Kashmir.", image: "https://picsum.photos/seed/Rawalakot/800/400" },
  { name: "Banjosa Lake", lat: 33.7167, lng: 73.6167, category: "lake", province: "AJK", rating: 4.5, bestTime: "March to November", description: "A beautiful reservoir surrounded by pine forests in the hills above Rawalakot, AJK. The lake offers boating, fishing, and pleasant forest walks. One of the most popular family destinations in Azad Kashmir.", history: "Banjosa Lake was developed as an artificial reservoir in the area's forested hills, reflecting the growing importance of domestic tourism for Azad Kashmir. The lake and surrounding forest are maintained by the AJK Forest Department.", image: "https://picsum.photos/seed/BanjosaLake/800/400" },
  { name: "Keran Village (AJK)", lat: 34.6061, lng: 73.9241, category: "mountain", province: "AJK", rating: 4.5, bestTime: "April to October", description: "A scenic village on the bank of the Neelum River, directly facing an Indian Army post on the opposite bank. The juxtaposition of beautiful natural landscape with the reality of divided Kashmir is striking. A tourist hub for the lower Neelum Valley region.", history: "One of the many villages divided by the Line of Control that partitioned families on both sides of the ceasefire line. For decades families could communicate only by shouting across the river. The village's riverside location and scenic beauty have made it a major tourist destination.", image: "https://picsum.photos/seed/KeranAJK/800/400" },
  { name: "Machiara National Park", lat: 34.6500, lng: 73.8500, category: "wildlife", province: "AJK", rating: 4.4, bestTime: "April to October", description: "Protects a significant area of Himalayan temperate forest important for Kashmir musk deer, Himalayan black bear, and leopard. Contains beautiful alpine meadows and streams. Several trekking routes pass through or near the park.", history: "Established in 1975 to protect the forested watershed of the Jhelum River in AJK. Represents the first systematic attempt at wildlife conservation in Azad Kashmir.", image: "https://picsum.photos/seed/MachiaraPark/800/400" },
  { name: "Mangla Dam", lat: 33.1500, lng: 73.6500, category: "historical", province: "AJK", rating: 4.3, bestTime: "All year", description: "One of the largest dams in the world on the Jhelum River in Mirpur district and a major electricity source for Pakistan. The beautiful reservoir (Mangla Lake) offers boating and water sports. The old city of Mirpur was submerged when the dam was built.", history: "Built between 1961-67 following the Indus Waters Treaty with India. The dam's construction submerged old Mirpur and displaced over 100,000 people — many of whom emigrated to the UK, establishing the large Mirpuri community in British cities like Birmingham and Bradford.", image: "https://picsum.photos/seed/ManglaDam/800/400" },
  { name: "Sudhan Gali", lat: 33.9667, lng: 73.6000, category: "mountain", province: "AJK", rating: 4.6, bestTime: "April to October", description: "A beautiful high-altitude meadow and viewpoint in the Poonch district of AJK, accessible via Rawalakot. The meadow offers panoramic views of surrounding mountains and is one of AJK's most scenic high points. A popular hiking and camping destination.", history: "Sudhan Gali is named after the Sudhan tribe that inhabits the Poonch district. The meadow has been used for summer grazing by local communities for centuries and has been developed as a tourism destination in recent decades.", image: "https://picsum.photos/seed/SudhanGali/800/400" },

  // ═══════════════════════════════════════════
  // MORE LOCAL PLACES — ALL REGIONS
  // ═══════════════════════════════════════════

  { name: "Tarbela Dam", lat: 34.0814, lng: 72.6547, category: "historical", province: "KPK", rating: 4.4, bestTime: "All year", description: "The world's largest earth-filled dam and one of the largest dams in the world by structural volume, built on the Indus River. The massive reservoir has transformed the region. The dam provides Pakistan with significant hydroelectric power and irrigation water.", history: "Built between 1968-1976 as part of the Indus Waters Treaty infrastructure with World Bank financing. At the time the world's largest earth-filled dam. Its construction required relocation of over 100,000 people from the reservoir area.", image: "https://picsum.photos/seed/TarbelaDam/800/400" },
  { name: "Taunsa Barrage Wildlife Sanctuary", lat: 30.5447, lng: 70.8428, category: "wildlife", province: "Punjab", rating: 4.1, bestTime: "November to March", description: "An important irrigation barrage on the Indus River in Muzaffargarh district. The barrage area is a critical habitat for the endangered Indus River dolphins (bhulan) — one of the world's rarest dolphins. The wetlands support large populations of wintering waterbirds.", history: "Completed in 1958 as part of Pakistan's post-independence irrigation infrastructure development. Designated a wildlife sanctuary primarily to protect the critically endangered Indus River dolphin, which is found only in specific sections of the Indus.", image: "https://picsum.photos/seed/TaunsaBarrage/800/400" },
  { name: "Torkham Border (Khyber)", lat: 34.0984, lng: 71.1119, category: "historical", province: "KPK", rating: 4.3, bestTime: "October to April", description: "The Torkham border crossing on the Khyber Pass is the busiest crossing point between Pakistan and Afghanistan. The sight of the constant flow of trucks, travelers, and traders crossing here is a fascinating window into the ancient commercial relationship between the two countries.", history: "Torkham has been the primary crossing point between the Khyber Pass and the Afghan territory of Nangarhar for centuries. During British rule it was a carefully monitored frontier post. In modern times it handles the bulk of overland trade between Pakistan and Afghanistan, representing the continuation of Silk Road commerce.", image: "https://picsum.photos/seed/TorkhamBorder/800/400" },
  { name: "Minwallay (Salt Range Lake)", lat: 32.5333, lng: 72.4833, category: "lake", province: "Punjab", rating: 4.2, bestTime: "October to March", description: "The Uchhali salt lake in the Salt Range hills of Punjab is a Ramsar-designated wetland site with extraordinary concentrations of breeding and wintering waterbirds. Flamingos, spoonbills, and numerous duck species make this one of the best birding sites in Pakistan.", history: "The salt lakes of the Punjab's Salt Range plateaus have been important saltwater resources for local communities for hundreds of years. Their conservation recognized at international level through Ramsar designation reflects their importance as wildlife habitat.", image: "https://picsum.photos/seed/UchhaliLake/800/400" },
  { name: "Gojra Wetlands", lat: 31.1500, lng: 72.6833, category: "wildlife", province: "Punjab", rating: 4.0, bestTime: "November to February", description: "The wetlands of central Punjab near Gojra are important wintering sites for migratory waterbirds following the Indus Flyway. Thousands of ducks, geese, and wading birds winter in these low-lying agricultural areas.", history: "The central Punjab wetlands have been important seasonal habitat for migratory birds since glacial periods. The area's wetland character has been modified by agricultural drainage but significant habitat remains in seasonal flooded areas.", image: "https://picsum.photos/seed/GojraWetlands/800/400" },
  { name: "Bhera (Historical Town)", lat: 32.4750, lng: 72.9156, category: "historical", province: "Punjab", rating: 4.2, bestTime: "October to March", description: "Bhera is one of the oldest continuously inhabited cities in Pakistan with a history going back at least 3,000 years. The city's ancient mosques, historical wells, and traditional architecture preserve a fascinating window into medieval Punjab. The 16th century mosque is particularly remarkable.", history: "Bhera is mentioned in ancient texts and has been an important city on the Grand Trunk Road since antiquity. It was significant in the Mughal period as a trading center. The city's preservation of traditional architecture makes it one of the most intact historical urban centers in Punjab.", image: "https://picsum.photos/seed/Bhera/800/400" },
  { name: "Pharwala Fort", lat: 33.6217, lng: 73.2936, category: "historical", province: "Punjab", rating: 4.3, bestTime: "October to March", description: "A largely unknown but impressive medieval fort near Islamabad, built by the Gakhar tribe that once controlled much of the Potohar Plateau. The stone fort perched on a rocky hill with a stream running through its foundations is one of the most atmospheric historical sites near the capital.", history: "Pharwala Fort was built by the Gakhars, a powerful Hindu Rajput tribe that converted to Islam and maintained control of the Potohar region for centuries. The Gakhars were important allies of successive Muslim rulers and remained powerful until the Sikh period.", image: "https://picsum.photos/seed/PharwalaFort/800/400" },
  { name: "Dhok Pathan Waterfall", lat: 33.4833, lng: 72.8167, category: "mountain", province: "Punjab", rating: 4.4, bestTime: "July to September (monsoon)", description: "One of the most beautiful natural waterfalls in the Potohar Plateau region, fed by monsoon rains. The waterfall cascades through a scenic rocky gorge and is a popular day trip from Islamabad and Rawalpindi. Most spectacular during and immediately after the monsoon season.", history: "The waterfall is a natural feature of the Soan River system that drains the Potohar Plateau. The area around the falls has archaeological significance with Paleolithic stone tool sites in the vicinity, evidence of some of the earliest human habitation in South Asia.", image: "https://picsum.photos/seed/DhokPathanWaterfall/800/400" },
  { name: "Gorakh Hill", lat: 26.9667, lng: 67.6167, category: "mountain", province: "Sindh", rating: 4.7, bestTime: "November to February (ski season Nov-Jan)", description: "Gorakh Hill is Sindh's highest point at 1,734m, an extraordinary destination for a province mostly known as a flat desert. In winter the hilltop experiences snowfall, making it a unique skiing destination. The views from the summit over the Indus plain extending to the horizon are extraordinary.", history: "Gorakh Hill was known to local communities and associated with the Sufi saint Gorakh Shah from whom it takes its name. The unique alpine microclimate at the summit was not widely recognized as a tourism opportunity until the 1990s. The mountain is sacred to both Hindu and Sufi Muslim communities.", image: "https://picsum.photos/seed/GorakHill/800/400" },
  { name: "Noori Abad Lake", lat: 25.0667, lng: 67.5000, category: "lake", province: "Sindh", rating: 4.1, bestTime: "November to February", description: "A lake near Hub district important for migratory waterfowl near the Sindh-Balochistan border. The lake attracts flamingos, pelicans, and various migratory duck species. The surrounding landscape of pink mudflats at sunset is extraordinarily beautiful.", history: "The lake is part of a cluster of wetland habitats near Karachi that support significant biodiversity. These coastal wetland areas have been important for fishing and bird hunting by local communities for generations.", image: "https://picsum.photos/seed/NooriAbadLake/800/400" },
  { name: "Hingol Mud Volcanoes", lat: 25.6070, lng: 65.5095, category: "mountain", province: "Balochistan", rating: 4.5, bestTime: "November to February", description: "Active mud volcanoes in Hingol National Park that periodically erupt with warm mud and gases. The surreal moonscape of mud cones and craters is one of the most unusual geological features in Pakistan. The Chandragup mud volcanoes are considered sacred by Hindu pilgrims.", history: "The mud volcanoes of Hingol are formed by pressurized gas and water forcing their way through soft sedimentary rock layers under the Makran coastal mountains. The Chandragup mud volcano near the Hinglaj temple has been venerated by Hindu pilgrims for centuries as a sacred natural phenomenon.", image: "https://picsum.photos/seed/HingolMudVolcano/800/400" },
  { name: "Ayub National Park, Rawalpindi", lat: 33.5958, lng: 73.0603, category: "wildlife", province: "Punjab", rating: 4.3, bestTime: "October to May", description: "A large urban park in Rawalpindi that was Pakistan's first national park. Contains a zoo, botanical garden, lake, and large forest areas. The park offers a pleasant green escape for Rawalpindi and Islamabad residents.", history: "Established as Rawalpindi National Park in 1956, renamed after President Ayub Khan. The park was developed on the grounds of the former British cantonment polo grounds and racing tracks. The Rawalpindi Zoo within the park is one of the oldest in Pakistan.", image: "https://picsum.photos/seed/AyubParkRwp/800/400" },
  { name: "Bahawalnagar (Fort Munro)", lat: 29.3700, lng: 70.7200, category: "historical", province: "Punjab", rating: 4.2, bestTime: "October to March", description: "Fort Munro is a hill station in the Sulaimaan Mountain Range, the highest peak in southeastern Punjab. The area offers striking views over the plains of Punjab and Balochistan. The British developed it as a sanatorium and hill station for the Punjab plains population.", history: "Fort Munro was developed by the British colonial administration in the late 19th century as a health resort and military sanatorium. The relatively cool temperatures and scenic mountain views made it a popular escape for the administrators of the Punjab and Balochistan frontier.", image: "https://picsum.photos/seed/FortMunro/800/400" },
  { name: "Koh Murdar (Quetta)", lat: 30.2000, lng: 66.9500, category: "mountain", province: "Balochistan", rating: 4.3, bestTime: "March to October", description: "Koh Murdar (literally 'Dead Mountain') is a significant peak in the mountains surrounding Quetta, offering panoramic views over the Quetta Valley and surrounding mountain ranges. A popular hiking destination for Quetta residents.", history: "The mountains surrounding Quetta have been important landmarks for navigation across the Balochistan plateau for centuries. The name 'Murdar' for the peak is of uncertain origin but appears in multiple historical maps and accounts of the Quetta area during the British period.", image: "https://picsum.photos/seed/KohMurdar/800/400" },
  { name: "Husn Abdal (Panja Sahib)", lat: 33.8200, lng: 72.6900, category: "religious", province: "Punjab", rating: 4.7, bestTime: "All year (March Baisakhi festival)", description: "Panja Sahib in Hasan Abdal is one of the most sacred Sikh pilgrimage sites in Pakistan, the fourth most important Sikh shrine in the world. The shrine contains the handprint (panja) of Guru Nanak said to be imprinted in the rock where he stopped a boulder. The Baisakhi festival attracts thousands of Sikh pilgrims from across the world.", history: "The shrine commemorates the miracle of Guru Nanak who, according to Sikh tradition, stopped a boulder rolling towards his disciples by pressing his hand against it, leaving an imprint in the rock. The site has been a Sikh pilgrimage destination since the early 16th century. Pakistan has facilitated Sikh pilgrimages to this site, demonstrating goodwill toward the Sikh diaspora.", image: "https://picsum.photos/seed/PanjaSahib/800/400" },
  { name: "Kartarpur Sahib Corridor", lat: 31.9206, lng: 75.0237, category: "religious", province: "Punjab", rating: 4.8, bestTime: "All year", description: "Kartarpur Sahib is the mosque where Guru Nanak Dev Ji spent the last 18 years of his life and where he died in 1539. The Kartarpur Corridor opened in 2019 allows Sikh pilgrims from India to visit without a visa — a remarkable act of peace diplomacy between the two countries.", history: "Guru Nanak Dev Ji (1469-1539) the founder of Sikhism established a commune at Kartarpur where he spent his final years farming and receiving visitors. He died here in 1539. The shrine has been one of the most sacred Sikh sites since the beginning of the religion. The corridor was opened in November 2019 to coincide with the 550th birth anniversary of Guru Nanak.", image: "https://picsum.photos/seed/KartarpurSahib/800/400" },
  { name: "Pasni Town", lat: 25.2630, lng: 63.4679, category: "beach", province: "Balochistan", rating: 4.1, bestTime: "November to February", description: "Pasni is a fishing town on the Makran coast with beautiful beaches and a seafood culture. The town is surrounded by the dramatic Makran coastal landscape with its distinctive rock formations and clear Arabian Sea waters.", history: "Pasni has been a major fishing settlement on the Makran coast for centuries. The Portuguese established a presence here in the 16th century as a stop on their India Ocean trade route. The Pakistan Navy maintains a base near Pasni and a small airport connects it to the rest of Pakistan.", image: "https://picsum.photos/seed/Pasni/800/400" },
  { name: "Hub Chowki", lat: 25.0500, lng: 66.9467, category: "city", province: "Balochistan", rating: 3.9, bestTime: "October to March", description: "Hub is an industrial town near the Sindh-Balochistan border, significant as the location of the Hub Industrial estate. The Hub River and neighboring Hub Dam provide recreation opportunities.", history: "Hub Chowki was historically the crossing point of the Hub River on the road between Karachi and Balochistan. The British developed it as a check-post town. After independence the area was developed industrially to serve Karachi's growing economy.", image: "https://picsum.photos/seed/HubChowki/800/400" },
  { name: "Chaman Border Crossing", lat: 30.9170, lng: 66.4520, category: "historical", province: "Balochistan", rating: 4.0, bestTime: "October to March", description: "Chaman is Pakistan's main border crossing with Afghanistan through the Quetta-Kandahar route. The busy frontier town has a distinctive character as a trade and transit hub. The bazaar reflects the blend of Pakistani and Afghan cultures.", history: "Chaman has been a border crossing point since the establishment of the Durand Line that demarcated the boundary between British India and Afghanistan in 1893. The town grew as a commercial hub for trade between Kandahar and Karachi. During the Afghan jihad (1980s) Chaman was a major route for supplies and refugees.", image: "https://picsum.photos/seed/Chaman/800/400" },
  { name: "Durand Line Exhibition", lat: 30.1200, lng: 66.9800, category: "historical", province: "Balochistan", rating: 4.0, bestTime: "October to March", description: "Quetta's historical significance as the administrative center of British Balochistan is preserved in several colonial-era buildings and the Quetta Cathedral. The city's architectural heritage reflects its importance as a strategic military and administrative center during the British period.", history: "Quetta became significant as the headquarters of the British Indian Army's Balochistan Field Force and the Quetta Command. The city was laid out as a planned cantonment with wide tree-lined streets. After the devastating 1935 earthquake that destroyed most of the city, it was rebuilt on a grid plan that survives today.", image: "https://picsum.photos/seed/QuettaHeritage/800/400" },
  { name: "Pir Ghaib Waterfalls", lat: 29.7000, lng: 67.3833, category: "mountain", province: "Balochistan", rating: 4.4, bestTime: "June to September (monsoon)", description: "Pir Ghaib is a remote canyon and waterfall system in the mountains east of Khuzdar, fed by monsoon rains. The narrow slot canyon with water cascading through it creates a dramatic landscape. The site has a sacred character and a local Sufi shrine nearby.", history: "Pir Ghaib (Disappeared Saint) is named after a Sufi saint who is said to have disappeared into the rock at this sacred waterfall. The site is associated with local Islamic folk traditions and is considered a place of spiritual power by the surrounding Baloch communities.", image: "https://picsum.photos/seed/PirGhaib/800/400" },
  { name: "Chashma Barrage", lat: 32.4540, lng: 71.3816, category: "historical", province: "Punjab", rating: 4.1, bestTime: "All year", description: "Chashma Barrage on the Indus River in the Mianwali district is an important irrigation structure and the Chashma Lake formed by the barrage is a significant wildlife habitat. WWF Pakistan runs a dolphin conservation project here.", history: "Chashma Barrage was completed in 1971 as part of Pakistan's comprehensive Indus Basin irrigation system. The lake and wetlands around the barrage have become important habitats for the critically endangered Indus River dolphin (Platanista gangetica minor) and numerous waterfowl.", image: "https://picsum.photos/seed/ChashmaDam/800/400" },
  { name: "Ghanche District (Baltistan)", lat: 35.2800, lng: 76.7500, category: "mountain", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "June to September", description: "Ghanche district in eastern Baltistan is home to spectacular mountain scenery including K2 and other Karakoram giants. The area includes Hushe Valley, Masherbrum, and Khaplu, offering some of Pakistan's finest trekking and mountaineering opportunities.", history: "Ghanche was historically part of the Khaplu and Shigar principalities of Baltistan. The area is inhabited by Balti people with a distinct culture, language, and architectural tradition. The area was opened to international trekkers in the 1970s when permits for Karakoram peaks became available.", image: "https://picsum.photos/seed/GhancheDistrict/800/400" },
  { name: "Hushe Valley", lat: 35.4167, lng: 76.4500, category: "valley", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "June to September", description: "Hushe Valley in eastern Baltistan offers spectacular mountain landscapes with views of Masherbrum and other major Karakoram peaks. The valley serves as the starting point for treks to Gondogoro La pass and K2 via an alternate route. Dense forests give way to spectacular glaciated terrain.", history: "Hushe Valley has been inhabited by Balti communities for centuries. The valley gained importance as a trekking and mountaineering hub in the 1970s when international expeditions began using Hushe as an alternate access route to the Karakoram peaks, particularly Masherbrum.", image: "https://picsum.photos/seed/HusheValley/800/400" },
  { name: "Gondogoro La", lat: 35.6667, lng: 76.5000, category: "mountain", province: "Gilgit-Baltistan", rating: 4.8, bestTime: "July to August", description: "Gondogoro La is a challenging high mountain pass at 5,585m on the route from Hushe Valley to Concordia, offering extraordinary views of K2 and multiple 8,000-meter peaks. The crossing requires technical climbing equipment and is one of the most spectacular high passes in the world.", history: "Gondogoro La was first used as an expedition route by mountaineering teams in the 20th century. The pass provides an alternate circuit route to K2 and Concordia, allowing trekkers to traverse from the Hushe Valley to the Baltoro Glacier without retracing steps. It is now one of Pakistan's most sought-after trekking challenges.", image: "https://picsum.photos/seed/GondogoroLa/800/400" },
  { name: "Masherbrum (K1) View", lat: 35.6389, lng: 76.3053, category: "mountain", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "June to September", description: "Masherbrum (7,821m) is one of the most beautiful and distinctive mountains in the Karakoram Range, visible from the Hushe Valley. Its pyramid-like summit and massive rock faces have made it one of the most admired mountains in Pakistan. The Masherbrum Base Camp trek is one of Pakistan's best.", history: "Masherbrum (K1) was the first peak measured in the Karakoram survey by the British in 1856, hence its original designation K1. It was first climbed by American W. Unsoeld and Pakistani N. A. Jafri in 1960. The mountain is considered one of the most aesthetically perfect in the Karakoram.", image: "https://picsum.photos/seed/Masherbrum/800/400" },
  { name: "Sadpara Lake", lat: 35.2333, lng: 75.6067, category: "lake", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "May to October", description: "A beautiful lake near Skardu surrounded by dramatic mountain scenery. The lake is the source of drinking water for Skardu town and also used for recreational activities like boating. Ancient rock inscriptions and Buddhist carvings on rocks near the lakeshore document the area's historical significance.", history: "The lake areas near Skardu contain some of the most important Silk Road rock inscriptions in the world, with carvings documenting travelers crossing the Karakoram from the 2nd to 12th centuries CE. Buddhist, Hindu, and early Islamic inscriptions are found in multiple scripts.", image: "https://picsum.photos/seed/SadparaLake/800/400" },
  { name: "Naltar Blue Lake", lat: 36.2000, lng: 74.1750, category: "lake", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "June to September", description: "The famous Blue Lake (Satrangi Lake) in Naltar Valley is extraordinarily beautiful with its vivid turquoise-blue color. The lake sits at high altitude surrounded by pine forests and rocky peaks. Three colored lakes (Blue, Red, and Green) in close proximity make Naltar one of the most remarkable lake destinations in Pakistan.", history: "The Naltar lakes formed in glacial cirques carved during the last Ice Age. Their distinctive colors are caused by different mineral deposits in the glacier-fed waters. The Blue Lake is by far the most impressive and has become one of the most photographed natural features in Northern Pakistan.", image: "https://picsum.photos/seed/NaltarBlueLake/800/400" },
  { name: "Phuparash Peak", lat: 36.2167, lng: 74.3500, category: "mountain", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "July to September", description: "Phuparash (6,574m) is a prominent peak in the Karakoram near Gilgit that is one of the more accessible high-altitude mountains for climbing. The base camp trek through Naltar Valley offers spectacular scenery. The peak offers views over the complex mountain terrain of the western Karakoram.", history: "Phuparash has been on the radar of high-altitude climbers since expeditions began exploring the Karakoram in the early 20th century. The peak is achievable for experienced mountaineers and has been climbed by Pakistani and international teams. It is considered a good acclimatization peak for aspirants to higher Karakoram objectives.", image: "https://picsum.photos/seed/Phuparash/800/400" },
  { name: "Passu Village", lat: 36.4672, lng: 74.8694, category: "valley", province: "Gilgit-Baltistan", rating: 4.6, bestTime: "May to October", description: "Passu village opposite the famous Passu Cones is a traditional Wakhi community with flower gardens, small guesthouses, and extraordinary mountain views. The village offers a more authentic experience than the tourist circuit and access to the Batura Glacier and Passu Cones trekking routes.", history: "Passu village has been inhabited by Wakhi-speaking people for many centuries, and was traditionally a waypoint for traders crossing the Karakoram. The construction of the Karakoram Highway in the 1970s dramatically changed the village's relationship to the outside world, bringing tourism while also changing traditional livelihoods.", image: "https://picsum.photos/seed/PassuVillage/800/400" },
  { name: "Immit Village (Ishkoman)", lat: 36.6333, lng: 73.6833, category: "valley", province: "Gilgit-Baltistan", rating: 4.4, bestTime: "June to September", description: "A beautiful remote village deep in the Ishkoman Valley, one of the least-visited but most beautiful areas in Pakistan. The village is surrounded by spectacular mountain scenery and the local Kho and Wakhi culture is well preserved. The journey to Immit itself through the Ghizer River gorge is scenic.", history: "Immit is one of the villages in the Ishkoman Valley that has maintained traditional lifestyles and community structures despite the changes brought by 20th century development and the opening of access roads. The area was historically under the suzerainty of the Mehtar of Chitral.", image: "https://picsum.photos/seed/ImmitVillage/800/400" },
  { name: "Barpu Glacier", lat: 36.3833, lng: 74.8667, category: "mountain", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "June to September", description: "Barpu Glacier near Hopar village in Nagar Valley offers excellent trekking with views of surrounding Karakoram peaks. The trek through the flower-covered ablation valley along the glacier's edge is one of the most enjoyable in the region.", history: "Barpu Glacier is one of many glaciers in the western Karakoram that have been measured and monitored since the late 19th century. The Hopar-Nagar area has been inhabited by Burusho-speaking people for centuries. The glacier trekking route became popular in the 1980s.", image: "https://picsum.photos/seed/BarpuGlacier/800/400" },
  { name: "Nagar Valley", lat: 36.2500, lng: 74.6167, category: "valley", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "April to October", description: "Nagar Valley faces Hunza across the Hunza River and offers magnificent views of Rakaposhi and other peaks. The valley is known for its apricot blossoms in spring and a slower-paced, less touristed alternative to Hunza. The Hopar Village and Barpu Glacier are Nagar's main trekking highlights.", history: "Nagar was historically a separate princely state from Hunza, with the two states engaged in a complex relationship of rivalry and alliance. Nagar's people are predominantly Ismaili Muslims, like Hunza. The state acceded to Pakistan in 1974 along with Hunza.", image: "https://picsum.photos/seed/NagarValley/800/400" },
  { name: "Danyore (Gilgit)", lat: 35.9500, lng: 74.3500, category: "historical", province: "Gilgit-Baltistan", rating: 4.2, bestTime: "April to October", description: "Danyore near Gilgit is famous for Buddhist rock carvings including a large Buddha image and inscriptions dating from the 5th-7th centuries CE. The site documents the area's importance as a center of Buddhism on the Silk Road.", history: "The rock carvings at Danyore are among the most significant Buddhist heritage sites in Gilgit-Baltistan, demonstrating the extent of Buddhist civilization in this region before the arrival of Islam. They are part of the larger corpus of Silk Road rock art that lines the Indus and Gilgit rivers.", image: "https://picsum.photos/seed/DanyorGilgit/800/400" },
  { name: "Sai Waterfall (Gilgit)", lat: 35.8833, lng: 74.3500, category: "mountain", province: "Gilgit-Baltistan", rating: 4.3, bestTime: "June to September", description: "A series of waterfalls in a side valley near Gilgit City, accessible by a short hike from the main road. The waterfalls and the cool valley are a popular escape for Gilgit residents during the hot summer months.", history: "Sai Waterfall valley has been used as a recreational area by Gilgit residents for generations as one of the closest natural escapes from the regional capital. The waterfalls are fed by snowmelt from the surrounding mountains.", image: "https://picsum.photos/seed/SaiWaterfall/800/400" },

  // ═══════════════════════════════════════════
  // ADDITIONAL — historic, cultural, nature
  // ═══════════════════════════════════════════

  { name: "Katas Raj Temples", lat: 32.6933, lng: 72.9067, category: "historical", province: "Punjab", rating: 4.6, bestTime: "October to March", description: "Katas Raj is a complex of Hindu temples of great antiquity surrounding a sacred lake. The Katas Lake is considered so sacred in Hinduism that it is mentioned in the Mahabharata. The oldest temple at the site is at least 1,700 years old. A significant pilgrimage site for Hindus in Pakistan.", history: "Katas Raj is associated with the legend that the tears of Lord Shiva, weeping for his dead wife Sati, formed the Katas Lake. The site is mentioned in the Mahabharata as one of the most sacred tirthastanas (pilgrimage sites) in the Panjab region. The temples represent multiple periods of Hindu religious construction from the 7th to 19th centuries CE.", image: "https://picsum.photos/seed/KatasRajTemple/800/400" },
  { name: "Khirther National Park (Karachi hills)", lat: 26.5000, lng: 67.6667, category: "wildlife", province: "Sindh", rating: 4.4, bestTime: "November to February", description: "Kirthar National Park lies near Karachi and offers rugged mountain trekking, wildlife including wild goats and leopards, and important archaeological sites from the Indus Valley Civilization. One of Pakistan's largest national parks.", history: "Established in 1974 as one of Pakistan's first batch of national parks, Kirthar protects an area of the Kirthar Range mountains that arc through eastern Sindh. The park contains important archaeological sites including Kahu-jo-Daro and ancient habitation sites from the Indus period.", image: "https://picsum.photos/seed/KirtharPark2/800/400" },
  { name: "Garam Chashma (Hot Springs, Chitral)", lat: 36.4167, lng: 71.8833, category: "mountain", province: "KPK", rating: 4.5, bestTime: "May to October", description: "Garam Chashma (Hot Springs) is a beautiful valley in Chitral with natural hot spring pools fed by geothermal water. The springs are set against dramatic mountain scenery with the Lutkho River rushing nearby. The hot springs are popular with trekkers and locals alike as a therapeutic experience.", history: "Garam Chashma has been used by the local Kho people for centuries for its therapeutic waters. The springs are fed by geothermal activity associated with the complex geology of the Hindu Kush mountains. The valley serves as an important base for trekking into the surrounding mountains including routes toward Broghil.", image: "https://picsum.photos/seed/GaramChashma/800/400" },
  { name: "Masjid Wazir Khan (Lahore)", lat: 31.5808, lng: 74.3264, category: "historical", province: "Punjab", rating: 4.8, bestTime: "October to March", description: "One of the most intricately decorated mosques in Pakistan from the Mughal period, featuring extraordinary kashi-kari tile mosaic work covering the entire facade in brilliant colors. The interior calligraphy and decorative painting are masterpieces of Mughal art.", history: "Built in 1635 under the patronage of Nawab Wazir Khan, the Governor of Lahore under Emperor Shah Jahan. The mosque is often cited as the finest example of Mughal decorative tilework in the world. The kashi-kari work covering it employs Persian calligraphy and floral motifs in a harmonious design.", image: "https://picsum.photos/seed/WazirKhanMosqueDetail/800/400" },
  { name: "Chita Katha Lake (Neelum)", lat: 34.7167, lng: 74.3333, category: "lake", province: "AJK", rating: 4.8, bestTime: "July to September", description: "An extraordinarily beautiful alpine lake in the upper Neelum Valley at high altitude, accessible only by a challenging multi-day trek. The pristine lake with crystal-clear water reflects surrounding peaks spectacularly. One of the most remote and beautiful lakes in Azad Kashmir.", history: "Chita Katha Lake is in a remote area that remained virtually unknown outside local communities until the early 21st century when improved trekking infrastructure made it accessible. The lake remains one of the hardest to reach major attractions in Pakistan, ensuring it maintains its pristine character.", image: "https://picsum.photos/seed/ChitaKathaLake/800/400" },
  { name: "Shounter Lake (AJK)", lat: 34.7667, lng: 74.4500, category: "lake", province: "AJK", rating: 4.7, bestTime: "July to September", description: "A beautiful high-altitude lake in the upper Neelum Valley, reachable via a challenging trek beyond Kel. The lake is set in spectacular alpine scenery and is one of the most pristine water bodies in Azad Kashmir. The surrounding meadows offer excellent camping.", history: "Shounter Lake is a glacial lake formed during the last ice age in a cirque above the Neelum Valley. The lake was known to local herdsmen who brought their livestock to the surrounding alpine pastures in summer. It became accessible to tourists only in the last two decades.", image: "https://picsum.photos/seed/ShounterLake/800/400" },
  { name: "Keran Wildlife Reserve (AJK)", lat: 34.5500, lng: 73.8500, category: "wildlife", province: "AJK", rating: 4.4, bestTime: "April to October", description: "The forests around Keran in Neelum Valley are protected as a wildlife reserve important for musk deer, black bear, and various bird species including the western tragopan (Pakistan's rarest bird). The dense forests and proximity to the Line of Control have kept the wildlife habitat relatively undisturbed.", history: "The forests of Neelum Valley have been protected as a wildlife reserve since 1975. The proximity to the Line of Control has paradoxically benefited wildlife conservation, as restricted access has limited hunting and habitat degradation in the border areas.", image: "https://picsum.photos/seed/KeranWildlife/800/400" },
  { name: "Lowari Top (Pass)", lat: 35.5167, lng: 71.8000, category: "mountain", province: "KPK", rating: 4.5, bestTime: "July to September (when open)", description: "Lowari Top at 3,118m is the mountain pass connecting Dir district with Chitral. For decades the pass was closed by snow for 6 months until the Lowari Tunnel was completed in 2017. The top of the pass still offers extraordinary views and is a popular spot in summer.", history: "The Lowari Pass was one of the most treacherous passes in Pakistan, causing isolation of Chitral for many months annually. Its opening and closing was a major event in Chitrali life. The construction of the tunnel below the pass was one of the most anticipated infrastructure projects in KPK's history.", image: "https://picsum.photos/seed/LowariPass/800/400" },
  { name: "Havelian (KPK)", lat: 34.0525, lng: 73.1511, category: "city", province: "KPK", rating: 4.0, bestTime: "March to November", description: "Havelian is a small town in Hazara division famous as the terminus of the historic Khyber Railway and as the starting point of the proposed KKH through the Indus gorge. The town has historical significance as a gateway to the Hazara region.", history: "Havelian was the terminus of the North-Western Railway's line from Rawalpindi, built during the British period. The railway to Havelian was the starting point for travelers heading north to Mansehra, Abbottabad, and beyond. The town has maintained its character as a transit point on the main north-south road through KPK.", image: "https://picsum.photos/seed/Havelian/800/400" },
  { name: "Chiniot (Historical Town)", lat: 31.7200, lng: 72.9783, category: "historical", province: "Punjab", rating: 4.4, bestTime: "October to March", description: "Chiniot is a small city in Punjab famous for its extraordinary woodwork furniture, a craft tradition going back centuries. The city's historical Shahi Mosque with its exquisite woodcarving and the unique architectural style of Chiniot buildings make it a distinctive heritage destination.", history: "Chiniot has been a center of traditional woodcraft since at least the Mughal period. The city's master woodworkers supplied furniture and decorative woodwork to the Mughal court. The craft tradition continues and Chiniot furniture is sold worldwide. The city also has historical mosques and shrines of significance.", image: "https://picsum.photos/seed/Chiniot/800/400" },
  { name: "Khunchkun Pass", lat: 36.5833, lng: 74.9167, category: "mountain", province: "Gilgit-Baltistan", rating: 4.3, bestTime: "July to September", description: "Khunchkun Pass is a high mountain pass accessible from the Gojal Valley, offering extraordinary views over the Karakoram glaciers and mountains. The pass is on an ancient route used by traders and herders between different valley systems in the northern Karakoram.", history: "The high passes of the Gojal Valley were traditionally used by the Wakhi people who herded yaks and cattle between valley pastures on a seasonal basis. The passes are part of a complex network of transhumant routes that have sustained mountain communities in this region for millennia.", image: "https://picsum.photos/seed/KhunchkunPass/800/400" },
  { name: "Chitta Kalas Meadow", lat: 35.5667, lng: 72.6333, category: "valley", province: "KPK", rating: 4.7, bestTime: "July to August", description: "Chitta Kalas is a stunning high-altitude meadow in the Swat Kohistan area near Kalam, accessible by a challenging trek. The brilliant white-floored meadow (chitta means white, kalas means above) surrounded by dark pine forests is extraordinary. Wildflower blooms in August are spectacular.", history: "Chitta Kalas meadow was known to local Kohistani herders who brought their flocks to these high pastures in summer. The meadow gained wider fame through social media in the 2010s and has become one of the most sought-after trekking destinations in Upper Swat.", image: "https://picsum.photos/seed/ChittaKalasMeadow/800/400" },
  { name: "Biafo Glacier", lat: 35.9333, lng: 75.4000, category: "mountain", province: "Gilgit-Baltistan", rating: 4.7, bestTime: "June to August", description: "Biafo Glacier is one of the world's longest glaciers outside polar regions at 67 km. It connects with the Hispar Glacier across the Hispar La pass, creating the world's longest glacier system outside polar regions. The Snow Lake at the head of Biafo is one of nature's most remarkable features.", history: "Biafo Glacier was first explored by Martin Conway in 1892 during the same expedition that reached Concordia. The glacier was mapped in detail by several early 20th century expeditions. The Biafo-Hispar connection creates a unique 'ice highway' across the Karakoram that has been a major trekking route since the 1970s.", image: "https://picsum.photos/seed/BiafogGlacier/800/400" },
  { name: "Snow Lake (Lukpe Lawo)", lat: 36.0500, lng: 75.2500, category: "mountain", province: "Gilgit-Baltistan", rating: 4.9, bestTime: "July to August", description: "Snow Lake (Lukpe Lawo) is an extraordinary glacial neve at the head of the Biafo Glacier at approximately 5,000m, covering about 75 sq km. The vast smooth expanse of snow surrounded by some of the Karakoram's highest peaks is one of the most remote and spectacular landscapes in the world.", history: "Snow Lake was first explored by Martin Conway's 1892 expedition. The explorer noted it resembled a frozen sea — a vast flat snowfield surrounded by high peaks on all sides. The Biafo Snow Lake trek (via Hispar) is considered one of the world's greatest glacier treks and typically takes 2-3 weeks.", image: "https://picsum.photos/seed/SnowLake/800/400" },
  { name: "Ishkoman Darkot Pass", lat: 36.7167, lng: 73.7000, category: "mountain", province: "Gilgit-Baltistan", rating: 4.5, bestTime: "July to September", description: "Darkot Pass at 4,847m connects the Yasin/Ishkoman valleys with the Yarkhun Valley in Chitral. One of the most historically important passes in the Hindu Kush, it was a key route between the Gilgit Agency and Chitral. The pass offers spectacular views of the surrounding massifs.", history: "Darkot Pass was used by the British explorer George Hayward when he was murdered in 1870 en route to explore territory beyond the Hindu Kush — a mystery that remains unsolved. The pass was an important British strategic route between Gilgit and Chitral and was guarded by local levies during the Great Game period.", image: "https://picsum.photos/seed/DarkotPass/800/400" },

];